import { GoogleGenAI } from "@google/genai";
import { MenuItem, Stall } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const generateSystemInstruction = (menuItems: MenuItem[], stalls: Stall[]) => `
You are "DineBot", the intelligent food assistant for DineTime at Bicol University Polangui Campus (BUPC).
Your goal is to help students and staff find food, recommend meals based on preferences, and answer questions about the menu.

Context Data:
Menu Items: ${JSON.stringify(menuItems.map(i => `${i.name} (${i.category}) - ₱${i.price} at ${i.stallName}. Attributes: ${i.isSpicy ? 'Spicy' : ''} ${i.isVeg ? 'Vegetarian' : ''}`))}
Stalls: ${JSON.stringify(stalls.map(s => s.name))}

Guidelines:
1. Be friendly, concise, and helpful.
2. Use Bicolano friendly tone occasionally if appropriate (like "Oragon!").
3. When recommending, suggest specific items from the provided menu.
4. If asked about prices, be accurate based on the data.
5. Emphasize the BUPC spirit (Blue & Orange).
6. Keep responses relatively short suitable for a chat interface.
`;

export const sendMessageToGemini = async (
  message: string,
  history: { role: 'user' | 'model'; text: string }[],
  menuItems: MenuItem[],
  stalls: Stall[]
): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: generateSystemInstruction(menuItems, stalls),
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const response = await chat.sendMessage({ message });
    return response.text || "I'm having trouble processing that right now. Try again?";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Sorry, I seem to be having connection issues. Please check your internet or try again later.";
  }
};

export const getSmartRecommendation = async (userPreferences: string, menuItems: MenuItem[]): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            config: {
                systemInstruction: "You are a recommendation engine. Based on the user's past history or preferences, suggest one specific meal from the menu provided previously. Return ONLY the name of the meal item.",
            },
            contents: `Menu: ${JSON.stringify(menuItems.map(i => i.name))}. User likes: ${userPreferences}. Recommend one item name.`
        });
        return response.text?.trim() || "";
    } catch (e) {
        return "";
    }
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate, useParams } from 'react-router-dom';
import { Home, UtensilsCrossed, ShoppingBag, User, Search, MapPin, Bell, ChevronLeft, LogOut, Clock, Phone, MapPin as LocationIcon, Filter, X, CreditCard, Banknote, Smartphone, CheckCircle, ChevronRight, Edit2, ClipboardList, Timer, Check, Loader, Coffee, Cake, Pizza, MessageSquare, Flame, Leaf } from 'lucide-react';
import { CartItem, MenuItem, Order, OrderStatus, User as UserType, Notification, PaymentMethod, Stall, Review } from './types';
import { CATEGORIES, MOCK_NOTIFICATIONS, STALLS, MENU_ITEMS, MOCK_REVIEWS } from './constants';
import { Button, ProductCard, Badge, Input, Select, StarRating, Modal } from './components/Components';
import { ChatBot } from './components/ChatBot';
import { supabase } from './services/supabase';
import { AnimatePresence, motion } from 'framer-motion';

// --- Page Transition Wrapper ---
const PageTransition: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.25, ease: "easeOut" }}
      className="min-h-screen"
    >
      {children}
    </motion.div>
  );
};

// --- Helper Functions to Map DB Types to App Types ---
const mapStall = (dbStall: any): Stall => ({
    id: dbStall.id,
    name: dbStall.name,
    image: dbStall.image,
    description: dbStall.description,
    phone: dbStall.phone,
    schedule: dbStall.schedule,
    openTime: dbStall.open_time,
    closeTime: dbStall.close_time,
    location: dbStall.location
});

const mapMenuItem = (dbItem: any, stalls: Stall[]): MenuItem => ({
    id: dbItem.id,
    name: dbItem.name,
    description: dbItem.description,
    price: dbItem.price,
    category: dbItem.category,
    image: dbItem.image,
    stallId: dbItem.stall_id,
    stallName: stalls.find(s => s.id === dbItem.stall_id)?.name || 'Unknown Stall',
    rating: dbItem.rating,
    calories: dbItem.calories,
    isPopular: dbItem.is_popular,
    isSpicy: dbItem.is_spicy,
    isVeg: dbItem.is_veg
});

const mapOrder = (dbOrder: any): Order => ({
    id: dbOrder.id,
    items: dbOrder.items,
    subtotal: dbOrder.items.reduce((acc: number, item: CartItem) => acc + (item.price * item.quantity), 0),
    fee: 15,
    total: dbOrder.total,
    status: dbOrder.status as OrderStatus,
    date: new Date(dbOrder.created_at),
    paymentMethod: dbOrder.payment_method as PaymentMethod
});

const mapReview = (dbReview: any): Review => ({
    id: dbReview.id,
    userId: dbReview.user_id,
    userName: dbReview.user_name || 'Anonymous',
    targetId: dbReview.target_id,
    targetType: dbReview.target_type,
    rating: dbReview.rating,
    comment: dbReview.comment,
    date: new Date(dbReview.created_at)
});

// --- Components ---

const BottomNav: React.FC<{ cartCount: number }> = ({ cartCount }) => {
  const location = useLocation();
  const isActive = (path: string) => location.pathname === path || (path !== '/' && location.pathname.startsWith(path));

  const navItems = [
    { icon: Home, label: 'Home', path: '/' },
    { icon: UtensilsCrossed, label: 'Menu', path: '/menu' },
    { icon: ShoppingBag, label: 'Cart', path: '/cart', badge: cartCount },
    { icon: User, label: 'Profile', path: '/profile' },
  ];

  if (['/login', '/signup', '/welcome'].includes(location.pathname)) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 pb-safe z-40 max-w-md mx-auto">
      <div className="flex justify-around items-center h-16">
        {navItems.map((item) => (
          <Link
            key={item.label}
            to={item.path}
            className={`flex flex-col items-center justify-center w-full h-full space-y-1 transition-all duration-200 ${
              isActive(item.path) ? 'text-bupc-blue' : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            <motion.div 
                whileTap={{ scale: 0.8 }}
                className={`relative p-1.5 rounded-xl transition-all ${isActive(item.path) ? 'bg-blue-50' : ''}`}
            >
              <item.icon size={22} strokeWidth={isActive(item.path) ? 2.5 : 2} />
              {item.badge ? (
                <span className="absolute -top-1 -right-1 bg-bupc-orange text-white text-[10px] font-bold w-4 h-4 flex items-center justify-center rounded-full border border-white">
                  {item.badge}
                </span>
              ) : null}
            </motion.div>
            <span className="text-[10px] font-medium">{item.label}</span>
          </Link>
        ))}
      </div>
    </div>
  );
};

const Header: React.FC<{ 
  title?: string; 
  showLocation?: boolean; 
  backUrl?: string;
  rightAction?: React.ReactNode 
}> = ({ title, showLocation, backUrl, rightAction }) => {
  const navigate = useNavigate();
  return (
    <header className="sticky top-0 z-30 bg-bupc-blue shadow-md text-white">
      <div className="px-4 h-14 flex items-center justify-between max-w-md mx-auto">
        {backUrl ? (
          <button onClick={() => navigate(backUrl)} className="p-1 -ml-1 text-white hover:bg-white/10 rounded-full">
            <ChevronLeft size={24} />
          </button>
        ) : showLocation ? (
          <div className="flex flex-col">
            <span className="text-[10px] text-blue-200 font-semibold uppercase tracking-wide">Location</span>
            <div className="flex items-center gap-1 font-bold text-sm">
              <MapPin size={14} className="text-bupc-orange" />
              BU Polangui Campus
            </div>
          </div>
        ) : (
          <h1 className="text-lg font-bold">{title}</h1>
        )}

        <div className="flex items-center gap-2">
          {rightAction}
          {!rightAction && showLocation && (
            <Link to="/notifications" className="relative p-2 rounded-full hover:bg-white/10 text-white">
              <Bell size={20} />
              <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full border border-bupc-blue"></span>
            </Link>
          )}
        </div>
      </div>
    </header>
  );
};

// --- Review Component ---
const ReviewSection: React.FC<{ targetId: string, targetType: 'stall' | 'menu_item', user: UserType | null }> = ({ targetId, targetType, user }) => {
    const [reviews, setReviews] = useState<Review[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newReview, setNewReview] = useState({ rating: 5, comment: '' });
    const [submitting, setSubmitting] = useState(false);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchReviews = async () => {
            const { data, error } = await supabase.from('reviews')
                .select('*')
                .eq('target_id', targetId)
                .order('created_at', { ascending: false });

            if (data && data.length > 0) {
                setReviews(data.map(mapReview));
            } else {
                setReviews(MOCK_REVIEWS.filter(r => r.targetId === targetId));
            }
            setLoading(false);
        };
        fetchReviews();

        const channel = supabase.channel(`reviews:${targetId}`)
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'reviews', filter: `target_id=eq.${targetId}` }, (payload) => {
                setReviews(prev => [mapReview(payload.new), ...prev]);
            })
            .subscribe();

        return () => { supabase.removeChannel(channel); };
    }, [targetId]);

    const handleSubmit = async () => {
        if (!user) {
            alert("You must be logged in to review.");
            return;
        }
        setSubmitting(true);

        const localReview: Review = {
            id: Date.now().toString(),
            userId: user.id,
            userName: user.name,
            targetId,
            targetType,
            rating: newReview.rating,
            comment: newReview.comment,
            date: new Date()
        };

        if (user.id === 'guest') {
            setReviews(prev => [localReview, ...prev]);
            alert("Review added! (Guest Mode)");
            setSubmitting(false);
            setIsModalOpen(false);
            setNewReview({ rating: 5, comment: '' });
            return;
        }

        const { error } = await supabase.from('reviews').insert([{
            user_id: user.id,
            user_name: user.name,
            target_id: targetId,
            target_type: targetType,
            rating: newReview.rating,
            comment: newReview.comment
        }]);

        if (error) {
            console.error("Review failed", error);
            setReviews(prev => [localReview, ...prev]);
            alert("Review added! (Saved locally - Connection issues)");
        } else {
             alert("Review submitted successfully!");
        }

        setSubmitting(false);
        setIsModalOpen(false);
        setNewReview({ rating: 5, comment: '' });
    };

    return (
        <div className="mt-6">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-gray-900 text-lg">Reviews ({reviews.length})</h3>
                <Button size="sm" variant="outline" onClick={() => setIsModalOpen(true)}>
                    Write Review
                </Button>
            </div>

            {loading ? (
                <div className="text-center py-4 text-gray-400">Loading reviews...</div>
            ) : reviews.length === 0 ? (
                <div className="text-center py-8 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                    <MessageSquare className="mx-auto text-gray-300 mb-2" />
                    <p className="text-gray-500 text-sm">No reviews yet. Be the first!</p>
                </div>
            ) : (
                <div className="space-y-4">
                    {reviews.map(review => (
                        <motion.div 
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            key={review.id} 
                            className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm"
                        >
                            <div className="flex justify-between items-start mb-2">
                                <div className="flex items-center gap-2">
                                    <div className="w-8 h-8 rounded-full bg-blue-100 text-bupc-blue flex items-center justify-center text-xs font-bold">
                                        {review.userName.charAt(0)}
                                    </div>
                                    <div>
                                        <span className="font-bold text-gray-900 text-sm block">{review.userName}</span>
                                        <span className="text-[10px] text-gray-400">{review.date.toLocaleDateString()}</span>
                                    </div>
                                </div>
                                <StarRating rating={review.rating} size={14} />
                            </div>
                            <p className="text-sm text-gray-600">{review.comment}</p>
                        </motion.div>
                    ))}
                </div>
            )}

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Write a Review">
                <div className="space-y-4">
                    <div className="flex flex-col items-center py-2">
                        <span className="text-sm text-gray-500 mb-2">Tap to rate</span>
                        <StarRating 
                            rating={newReview.rating} 
                            interactive 
                            size={32} 
                            onChange={(r) => setNewReview({ ...newReview, rating: r })} 
                        />
                    </div>
                    <textarea
                        className="w-full h-32 p-3 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-bupc-blue focus:outline-none resize-none"
                        placeholder="Share your experience..."
                        value={newReview.comment}
                        onChange={(e) => setNewReview({ ...newReview, comment: e.target.value })}
                    />
                    <Button className="w-full" onClick={handleSubmit} disabled={submitting}>
                        {submitting ? 'Submitting...' : 'Submit Review'}
                    </Button>
                </div>
            </Modal>
        </div>
    );
};


// --- Pages ---

const WelcomePage: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [step, setStep] = useState(0);

  const steps = [
    {
      title: "Welcome to DineTime",
      desc: "The smartest way to order food at Bicol University Polangui Campus.",
      img: "https://cdn-icons-png.flaticon.com/512/3075/3075977.png" 
    },
    {
      title: "Skip the Line",
      desc: "Order ahead from your favorite campus stalls and pick up when ready.",
      img: "https://cdn-icons-png.flaticon.com/512/2921/2921822.png" 
    },
    {
      title: "AI Powered Cravings",
      desc: "Not sure what to eat? Ask DineBot for personalized recommendations!",
      img: "https://cdn-icons-png.flaticon.com/512/4712/4712109.png" 
    }
  ];

  return (
    <PageTransition>
      <div className="h-screen bg-white flex flex-col items-center justify-between p-8 text-center max-w-md mx-auto">
        <div className="flex-1 flex flex-col items-center justify-center">
