             key={`d-${step}`}
             initial={{ opacity: 0 }}
             animate={{ opacity: 1 }}
             className="text-gray-500"
          >
            {steps[step].desc}
          </motion.p>
        </div>

        <div className="w-full space-y-6">
          <div className="flex justify-center gap-2">
            {steps.map((_, i) => (
              <div key={i} className={`h-2 rounded-full transition-all duration-300 ${i === step ? 'w-8 bg-bupc-orange' : 'w-2 bg-gray-200'}`} />
