            {step === steps.length - 1 ? "Get Started" : "Next"}
          </Button>
        </div>
      </div>
    </PageTransition>
  );
};

const AuthPage: React.FC<{ mode: 'login' | 'signup', onGuestLogin: () => void }> = ({ mode, onGuestLogin }) => {
  const [isLogin, setIsLogin] = useState(mode === 'login');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const [formData, setFormData] = useState({
      email: '',
      password: '',
      name: '',
      userType: 'Student',
      course: ''
  });

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setMessage('');

    try {
        if (isLogin) {
            const { error } = await supabase.auth.signInWithPassword({
                email: formData.email,
                password: formData.password
            });
            if (error) throw error;
        } else {
            const { data: authData, error: authError } = await supabase.auth.signUp({
                email: formData.email,
                password: formData.password,
                options: {
                    data: {
                        full_name: formData.name,
                        user_type: formData.userType,
                        course: formData.course
                    }
                }
            });
            if (authError) throw authError;

            if (authData.user && !authData.session) {
                setMessage("Account created! Please check your email inbox to verify your account.");
                setIsLogin(true);
                setLoading(false);
                return;
            }

            if (authData.user) {
                await supabase.from('profiles').upsert([
                    {
                        id: authData.user.id,
                        email: formData.email,
                        name: formData.name,
                        user_type: formData.userType,
                        course: formData.course,
                        avatar: `https://ui-avatars.com/api/?name=${formData.name}&background=random`
                    }
                ]);
            }
        }
    } catch (err: any) {
        setError(err.message || "An unexpected error occurred");
    } finally {
        setLoading(false);
    }
  };

  return (
    <PageTransition>
      <div className="min-h-screen bg-white p-6 flex flex-col justify-center max-w-md mx-auto">
        <div className="flex justify-center mb-8">
          <motion.div 
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center border-2 border-bupc-blue/10"
          >
             <div className="w-16 h-16 bg-bupc-blue rounded-full flex items-center justify-center text-white shadow-lg">
                <UtensilsCrossed size={32} />
             </div>
          </motion.div>
        </div>

        <div className="mb-6 text-center">
          <h1 className="text-3xl font-bold text-bupc-blue mb-2">{isLogin ? 'Welcome Back!' : 'Join DineTime'}</h1>
          <p className="text-gray-500">{isLogin ? 'Sign in to continue.' : 'Create an account.'}</p>
        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          {!isLogin && (
             <Input label="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required />
          )}
          <Input label="Email" type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} required />
          <Input label="Password" type="password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required />

          {!isLogin && (
             <div className="grid grid-cols-2 gap-4">
               <Select options={[{value: 'Student', label: 'Student'}, {value: 'Faculty', label: 'Faculty'}]} label="User Type" value={formData.userType} onChange={e => setFormData({...formData, userType: e.target.value})} />
               <Input label="Course/Dept" value={formData.course} onChange={e => setFormData({...formData, course: e.target.value})} />
             </div>
          )}

          {error && <p className="text-red-500 text-sm bg-red-50 p-2 rounded">{error}</p>}
          {message && <p className="text-green-600 text-sm bg-green-50 p-2 rounded">{message}</p>}

          <Button type="submit" className="w-full mt-4 h-12" disabled={loading}>
            {loading ? <Loader className="animate-spin" /> : (isLogin ? 'Sign In' : 'Sign Up')}
          </Button>
        </form>

        <div className="mt-4">
          <div className="relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-200"></div></div><div className="relative flex justify-center text-sm"><span className="px-2 bg-white text-gray-500">Or</span></div></div>
          <Button type="button" variant="outline" className="w-full mt-4" onClick={onGuestLogin}>Continue as Guest</Button>
        </div>

        <div className="mt-8 text-center text-sm">
          <span className="text-gray-500">{isLogin ? "New here? " : "Joined already? "}</span>
          <button onClick={() => { setIsLogin(!isLogin); setError(''); setMessage(''); }} className="font-bold text-bupc-blue">
            {isLogin ? 'Sign Up' : 'Log In'}
          </button>
        </div>
      </div>
    </PageTransition>
  );
};

const SearchPage: React.FC<{ addToCart: (item: MenuItem) => void, menuItems: MenuItem[] }> = ({ addToCart, menuItems }) => {
  const [query, setQuery] = useState('');
  const [priceRange, setPriceRange] = useState<'all' | 'under50' | '50to100' | 'above100'>('all');
  const [activeCat, setActiveCat] = useState('All');
  const navigate = useNavigate();

  const filteredItems = menuItems.filter(item => {
    const matchesQuery = item.name.toLowerCase().includes(query.toLowerCase());
    const matchesCat = activeCat === 'All' || item.category === activeCat;
    let matchesPrice = true;
    if (priceRange === 'under50') matchesPrice = item.price < 50;
    if (priceRange === '50to100') matchesPrice = item.price >= 50 && item.price <= 100;
    if (priceRange === 'above100') matchesPrice = item.price > 100;
    return matchesQuery && matchesCat && matchesPrice;
  });

  return (
    <PageTransition>
      <div className="bg-gray-50 min-h-screen pb-20">
        <div className="bg-white p-4 sticky top-0 z-20 shadow-sm">
          <div className="flex items-center gap-3 mb-4">
