               <input autoFocus type="text" placeholder="Search meals..." className="w-full bg-gray-100 rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-bupc-blue outline-none" value={query} onChange={e => setQuery(e.target.value)} />
             </div>
