const OrderStatusStepper = ({ currentStatus }: { currentStatus: OrderStatus }) => {
    const steps = [
        { id: OrderStatus.PENDING, label: 'Received', icon: ClipboardList },
        { id: OrderStatus.PREPARING, label: 'Cooking', icon: Timer },
        { id: OrderStatus.READY, label: 'Ready', icon: CheckCircle },
        { id: OrderStatus.COMPLETED, label: 'Done', icon: Check },
    ];
    const currentStep = steps.findIndex(s => s.id === currentStatus);
    return (
        <div className="flex items-center justify-between w-full px-2 mb-8 mt-2">
            {steps.map((step, index) => {
                const isActive = index <= currentStep;
                return (
                    <React.Fragment key={step.id}>
                        <div className="flex flex-col items-center gap-2 relative z-10 w-16">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${isActive ? 'bg-bupc-blue border-bupc-blue text-white shadow-lg' : 'bg-white border-gray-200 text-gray-300'}`}><step.icon size={18} /></div>
                            <span className={`text-[10px] font-bold absolute -bottom-6 w-24 text-center ${isActive ? 'text-bupc-blue' : 'text-gray-300'}`}>{step.label}</span>
                        </div>
                        {index < steps.length - 1 && <div className={`flex-1 h-0.5 -mt-4 mx-[-10px] ${index < currentStep ? 'bg-bupc-blue' : 'bg-gray-200'}`} />}
                    </React.Fragment>
                )
            })}
        </div>
    );
};

