const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>(MOCK_NOTIFICATIONS);
  const [hasSeenWelcome, setHasSeenWelcome] = useState(false);
  const [isGuest, setIsGuest] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [authLoading, setAuthLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    supabase.from('stalls').select('*').then(({ data }) => data && setStalls(data.map(mapStall)));
    supabase.from('menu_items').select('*').then(({ data }) => data && setMenuItems(data.map(i => mapMenuItem(i, stalls))));
    if (stalls.length === 0) { setStalls(STALLS); setMenuItems(MENU_ITEMS); }
  }, []);

  useEffect(() => {
      supabase.auth.getSession().then(({ data: { session } }) => {
          if (session?.user) {
              supabase.from('profiles').select('*').eq('id', session.user.id).single().then(({ data }) => {
                  if (data) {
                      setUser({ id: data.id, name: data.name, email: data.email, avatar: data.avatar, userType: data.user_type as any, course: data.course, age: data.age, address: data.address, phone: data.phone });
                      supabase.from('orders').select('*').eq('user_id', data.id).order('created_at', { ascending: false }).then(({ data: o }) => o && setOrders(o.map(mapOrder)));
                  }
                  setAuthLoading(false);
              });
          } else setAuthLoading(false);
      });
  }, []);

  const placeOrder = async (items: CartItem[], method: PaymentMethod) => {
    if (!user) return;
    const total = items.reduce((s, i) => s + (i.price * i.quantity), 0) + 15;
    const tempId = `ORD-${Date.now().toString().slice(-6)}`;
    const newOrder: Order = { id: tempId, items, subtotal: total-15, fee: 15, total, status: OrderStatus.PENDING, date: new Date(), paymentMethod: method };
    setOrders(prev => [newOrder, ...prev]);
    if (isGuest) return;
    try {
        const { data, error } = await supabase.from('orders').insert([{ user_id: user.id, items, total, payment_method: method, status: 'Pending' }]).select().single();
        if (error) throw error;
        if (data) setOrders(prev => prev.map(o => o.id === tempId ? mapOrder(data) : o));
    } catch (err: any) {
        console.error("Order placement error:", err.message);
        alert(`Order placement failed: ${err.message}`);
    }
  };

  if (authLoading) return <div className="h-screen flex items-center justify-center font-bold text-bupc-blue animate-pulse">DineTime...</div>;

  return (
    <div className="bg-white min-h-screen max-w-md mx-auto shadow-2xl relative font-sans text-gray-900">
      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!hasSeenWelcome ? <Route path="*" element={<WelcomePage onComplete={() => setHasSeenWelcome(true)} />} /> : 
           !user ? <><Route path="/login" element={<AuthPage mode="login" onGuestLogin={() => { setUser({ id: 'guest', name: 'Guest', email: '', avatar: 'https://ui-avatars.com/api/?name=Guest', userType: 'Student' }); setIsGuest(true); }} />} /><Route path="*" element={<AuthPage mode="login" onGuestLogin={() => { setUser({ id: 'guest', name: 'Guest', email: '', avatar: 'https://ui-avatars.com/api/?name=Guest', userType: 'Student' }); setIsGuest(true); }} />} /></> : 
           <>
              <Route path="/" element={<HomePage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} />} />
              <Route path="/menu" element={<MenuPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} />} />
              <Route path="/cart" element={<CartPage cart={cart} updateQty={(id, d) => setCart(prev => prev.map(i => i.id === id ? {...i, quantity: Math.max(0, i.quantity+d)} : i).filter(i => i.quantity > 0))} clearCart={() => setCart([])} placeOrder={placeOrder} />} />
              <Route path="/profile" element={<ProfilePage user={user} onLogout={() => setUser(null)} />} />
              <Route path="/profile/edit" element={<EditProfilePage user={user} onUpdate={setUser} />} />
              <Route path="/orders" element={<OrdersPage orders={orders} />} />
              <Route path="/orders/:id" element={<OrderDetailsPage orders={orders} />} />
              <Route path="/stalls/:id" element={<StallDetailsPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} user={user} />} />
              <Route path="/food/:id" element={<FoodDetailsPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} user={user} />} />
           </>}
        </Routes>
      </AnimatePresence>
      {user && <BottomNav cartCount={cart.length} />}
      {user && <ChatBot menuItems={menuItems} stalls={stalls} />}
    </div>
  );
};

const App: React.FC = () => (<HashRouter><AppContent /></HashRouter>);
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { MessageCircle, X, Send, Bot, User, Loader2 } from 'lucide-react';
import { ChatMessage, MenuItem, Stall } from '../types';
import { sendMessageToGemini } from '../services/geminiService';
import { Button } from './Components';
import { AnimatePresence, motion } from 'framer-motion';

interface ChatBotProps {
  menuItems: MenuItem[];
  stalls: Stall[];
}

export const ChatBot: React.FC<ChatBotProps> = ({ menuItems, stalls }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Hi! I\'m **DineBot**. Ask me anything about the menu!',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    const responseText = await sendMessageToGemini(input, messages.map(m => ({ role: m.role, text: m.text })), menuItems, stalls);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: responseText, timestamp: new Date() }]);
    setIsLoading(false);
  };

  const formatMessageText = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) return <strong key={index}>{part.slice(2, -2)}</strong>;
      return <span key={index}>{part}</span>;
    });
  };

  return (
    <>
      <AnimatePresence>
        {!isOpen && (
          <motion.button
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            exit={{ scale: 0 }}
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            onClick={() => setIsOpen(true)}
            className="fixed bottom-24 right-4 z-50 w-14 h-14 bg-bupc-blue text-white rounded-full shadow-2xl flex items-center justify-center"
          >
            <MessageCircle size={28} />
          </motion.button>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 100, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 100, scale: 0.95 }}
            className="fixed bottom-24 right-4 left-4 sm:left-auto sm:w-96 h-[480px] bg-white rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.2)] z-50 flex flex-col overflow-hidden border border-gray-100"
          >
            <div className="bg-bupc-blue text-white p-4 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center"><Bot size={18} /></div>
                <div><h3 className="font-bold text-sm">DineBot</h3><p className="text-[10px] text-blue-200">Online Assistant</p></div>
              </div>
              <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={20} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                  <div className={`max-w-[85%] rounded-2xl px-4 py-2.5 text-sm ${msg.role === 'user' ? 'bg-bupc-orange text-white rounded-tr-none' : 'bg-white text-gray-800 border border-gray-200 rounded-tl-none'}`}>
                    {formatMessageText(msg.text)}
                  </div>
                </div>
              ))}
              {isLoading && <div className="flex gap-2"><div className="bg-white border border-gray-100 rounded-2xl px-4 py-2 flex gap-1"><span className="w-1.5 h-1.5 bg-bupc-blue rounded-full animate-bounce"></span><span className="w-1.5 h-1.5 bg-bupc-blue rounded-full animate-bounce delay-75"></span></div></div>}
              <div ref={messagesEndRef} />
            </div>
            <div className="p-3 bg-white border-t border-gray-100 flex gap-2">
              <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} placeholder="Ask DineBot..." className="flex-1 bg-gray-100 rounded-full px-4 text-sm focus:ring-2 focus:ring-bupc-blue outline-none" />
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="w-10 h-10 bg-bupc-blue text-white rounded-full flex items-center justify-center disabled:opacity-50"><Send size={16} /></button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

