// --- Stepper for Order Status ---
const OrderStatusStepper = ({ currentStatus }: { currentStatus: OrderStatus }) => {
    const steps = [
        { id: OrderStatus.PENDING, label: 'Placed', icon: ClipboardList },
        { id: OrderStatus.PREPARING, label: 'Cooking', icon: Timer },
        { id: OrderStatus.READY, label: 'Ready', icon: CheckCircle },
        { id: OrderStatus.COMPLETED, label: 'Picked Up', icon: Check },
    ];
    const currentStep = steps.findIndex(s => s.id === currentStatus);

    return (
        <div className="flex items-center justify-between w-full px-2 mb-10 mt-6">
            {steps.map((step, index) => {
                const isCompleted = index < currentStep;
                const isActive = index === currentStep;
                return (
                    <React.Fragment key={step.id}>
                        <div className="flex flex-col items-center gap-2 relative z-10">
                            <motion.div 
                                animate={isActive ? { scale: [1, 1.1, 1] } : {}}
                                transition={{ repeat: Infinity, duration: 2 }}
                                className={`w-12 h-12 rounded-2xl flex items-center justify-center border-2 transition-all duration-500 ${
                                    isCompleted ? 'bg-green-500 border-green-500 text-white' : 
                                    isActive ? 'bg-bupc-blue border-bupc-blue text-white shadow-xl shadow-blue-200' : 
                                    'bg-white border-gray-200 text-gray-300'
                                }`}
                            >
                                {isCompleted ? <Check size={20} /> : <step.icon size={20} />}
                            </motion.div>
                            <span className={`text-[10px] font-bold absolute -bottom-6 w-20 text-center ${
                                index <= currentStep ? 'text-gray-900' : 'text-gray-400'
                            }`}>
                                {step.label}
                            </span>
                        </div>
                        {index < steps.length - 1 && (
                            <div className="flex-1 h-0.5 mx-[-10px] bg-gray-100 relative overflow-hidden">
                                <motion.div 
                                    initial={{ width: 0 }}
                                    animate={{ width: isCompleted ? '100%' : '0%' }}
                                    className="absolute inset-0 bg-green-500"
                                />
                            </div>
                        )}
                    </React.Fragment>
                )
            })}
        </div>
    );
};

