              {isLoading && (
                <div className="flex gap-2">
                    <div className="bg-white border border-gray-100 rounded-2xl px-4 py-3 flex gap-1.5 shadow-sm">
                        <motion.span animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1 }} className="w-1.5 h-1.5 bg-bupc-blue rounded-full"></motion.span>
