// --- Helper Functions to Map DB Types to App Types ---
const mapStall = (dbStall: any): Stall => ({
    id: dbStall.id,
    name: dbStall.name,
    image: dbStall.image,
    description: dbStall.description,
    phone: dbStall.phone,
    schedule: dbStall.schedule,
    openTime: dbStall.open_time,
    closeTime: dbStall.close_time,
    location: dbStall.location
});

const mapMenuItem = (dbItem: any, stalls: Stall[]): MenuItem => ({
    id: dbItem.id,
    name: dbItem.name,
    description: dbItem.description,
    price: dbItem.price,
    category: dbItem.category,
    image: dbItem.image,
    stallId: dbItem.stall_id,
    stallName: stalls.find(s => s.id === dbItem.stall_id)?.name || 'Unknown Stall',
    rating: dbItem.rating,
    calories: dbItem.calories,
    isPopular: dbItem.is_popular,
    isSpicy: dbItem.is_spicy,
    isVeg: dbItem.is_veg
});

const mapOrder = (dbOrder: any): Order => ({
    id: dbOrder.id.toString(),
    items: dbOrder.items,
    subtotal: dbOrder.items.reduce((acc: number, item: CartItem) => acc + (item.price * item.quantity), 0),
    fee: 15,
    total: dbOrder.total,
    status: dbOrder.status as OrderStatus,
    date: new Date(dbOrder.created_at),
    paymentMethod: dbOrder.payment_method as PaymentMethod
});

const mapReview = (dbReview: any): Review => ({
    id: dbReview.id,
    userId: dbReview.user_id,
    userName: dbReview.user_name || 'Anonymous',
    targetId: dbReview.target_id,
    targetType: dbReview.target_type,
    rating: dbReview.rating,
    comment: dbReview.comment,
    date: new Date(dbReview.created_at)
});

