const CartPage: React.FC<{ cart: CartItem[], updateQty: (id: string, d: number) => void, clearCart: () => void, placeOrder: (items: CartItem[], method: PaymentMethod) => void }> = ({ cart, updateQty, clearCart, placeOrder }) => {
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('GCash');
  const navigate = useNavigate();
  const subtotal = cart.reduce((s, i) => s + (i.price * i.quantity), 0);
  const fee = 15;
  const total = subtotal + fee;

  const handleCheckout = () => {
    placeOrder(cart, paymentMethod);
    clearCart();
    navigate('/orders');
  };

  if (cart.length === 0) return (
    <PageTransition>
      <Header title="My Cart" />
      <div className="p-10 text-center py-20 bg-white">
          <ShoppingBag size={64} className="mx-auto mb-6 text-gray-100" />
          <h3 className="text-xl font-black text-gray-900">Your cart is empty</h3>
          <p className="text-gray-400 mt-2 mb-8">Ready to discover something delicious?</p>
          <Button onClick={() => navigate('/menu')}>Start Ordering</Button>
      </div>
    </PageTransition>
  );

  return (
    <PageTransition>
      <Header title="My Cart" />
      <div className="p-4 space-y-6">
        <div className="space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-3 rounded-3xl border border-gray-100 shadow-sm">
              <img src={item.image} className="w-20 h-20 rounded-2xl object-cover" />
              <div className="flex-1 flex flex-col justify-between">
                <div>
                  <h4 className="font-bold text-gray-900">{item.name}</h4>
                  <p className="text-[10px] text-gray-400 font-bold uppercase">{item.stallName}</p>
                </div>
                <div className="flex items-center justify-between">
                  <span className="font-black text-bupc-blue">₱{item.price * item.quantity}</span>
                  <div className="flex items-center gap-3">
                    <button onClick={() => updateQty(item.id, -1)} className="w-8 h-8 rounded-full border border-gray-100 flex items-center justify-center">-</button>
                    <span className="font-bold text-sm">{item.quantity}</span>
                    <button onClick={() => updateQty(item.id, 1)} className="w-8 h-8 rounded-full bg-gray-900 text-white flex items-center justify-center">+</button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="bg-gray-50 p-6 rounded-[2rem] space-y-4">
          <h3 className="font-black text-gray-900 uppercase tracking-wider text-xs">Payment Method</h3>
          <div className="grid grid-cols-3 gap-2">
            {['GCash', 'PayMaya', 'Cash'].map(method => (
              <button 
                key={method} 
                onClick={() => setPaymentMethod(method as PaymentMethod)}
                className={`p-3 rounded-2xl flex flex-col items-center gap-2 border-2 transition-all ${
                  paymentMethod === method ? 'bg-white border-bupc-blue shadow-md' : 'bg-transparent border-transparent text-gray-400'
                }`}
              >
                {method === 'GCash' && <Smartphone size={18} />}
                {method === 'PayMaya' && <Banknote size={18} />}
                {method === 'Cash' && <Banknote size={18} />}
                <span className="text-[10px] font-black uppercase">{method}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2.5rem] border border-gray-100 space-y-3">
          <div className="flex justify-between text-sm text-gray-500">
            <span>Subtotal</span>
            <span className="font-bold text-gray-900">₱{subtotal}</span>
          </div>
          <div className="flex justify-between text-sm text-gray-500">
            <span>Platform Fee</span>
            <span className="font-bold text-gray-900">₱{fee}</span>
          </div>
          <div className="pt-3 border-t border-dashed border-gray-100 flex justify-between items-center">
            <span className="font-black text-gray-900">Total Amount</span>
            <span className="font-black text-bupc-orange text-2xl">₱{total}</span>
          </div>
          <Button className="w-full h-14 rounded-2xl mt-4" onClick={handleCheckout}>Place Order</Button>
        </div>
      </div>
    </PageTransition>
  );
};

