// --- Main App Logic (AppContent) ---

const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [hasSeenWelcome, setHasSeenWelcome] = useState(false);
  const [isGuest, setIsGuest] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [authLoading, setAuthLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    supabase.from('stalls').select('*').then(({ data }) => data && setStalls(data.map(mapStall)));
    supabase.from('menu_items').select('*').then(({ data }) => data && setMenuItems(data.map(i => mapMenuItem(i, stalls))));
    if (stalls.length === 0) { setStalls(STALLS); setMenuItems(MENU_ITEMS); }
  }, []);

  useEffect(() => {
      supabase.auth.getSession().then(({ data: { session } }) => {
          if (session?.user) {
              supabase.from('profiles').select('*').eq('id', session.user.id).single().then(({ data }) => {
                  if (data) {
                      setUser({ id: data.id, name: data.name, email: data.email, avatar: data.avatar, userType: data.user_type as any, course: data.course, age: data.age, address: data.address, phone: data.phone });
                      supabase.from('orders').select('*').eq('user_id', data.id).order('created_at', { ascending: false }).then(({ data: o }) => o && setOrders(o.map(mapOrder)));
                  }
                  setAuthLoading(false);
              });
          } else setAuthLoading(false);
      });
  }, []);

  const placeOrder = async (items: CartItem[], method: PaymentMethod) => {
    if (!user) return;
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const tempId = `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;

    const newOrder: Order = { 
        id: tempId, 
        items, 
        subtotal, 
        fee: 15, 
        total, 
        status: OrderStatus.PENDING, 
        date: new Date(), 
        paymentMethod: method 
    };

    // Preemptively add to local state for instant feedback
    setOrders(prev => [newOrder, ...prev]);

    if (isGuest) {
        alert("Guest order placed locally! In a real app, this would be saved to a database.");
        return;
    }

    try {
        const payload = { 
            user_id: user.id, 
            items: items, 
            total: total, 
            payment_method: method, 
            status: 'Pending' 
        };

        const { data, error } = await supabase.from('orders').insert([payload]).select().single();

        if (error) {
            // Log full error object for debugging
            console.error("Supabase Order Error:", error);
            throw new Error(error.message || JSON.stringify(error));
        }

        if (data) {
            // Update the temporary order with real DB data (ID, created_at)
            setOrders(prev => prev.map(o => o.id === tempId ? mapOrder(data) : o));
        }
    } catch (err: any) {
        const errorMsg = err.message || "Unknown error during checkout";
        console.error("Order placement failed:", errorMsg);
        alert(`Order placement failed: ${errorMsg}. Your order is saved locally for this session.`);
    }
  };

  if (authLoading) return (
    <div className="h-screen flex items-center justify-center bg-white flex-col gap-4">
        <div className="w-16 h-16 bg-bupc-blue rounded-3xl flex items-center justify-center text-white shadow-2xl animate-pulse">
            <UtensilsCrossed size={32} />
        </div>
        <p className="font-black text-bupc-blue uppercase tracking-widest text-xs">DineTime Loading</p>
    </div>
  );

  return (
    <div className="bg-white min-h-screen max-w-md mx-auto shadow-2xl relative font-sans text-gray-900 overflow-x-hidden">
      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!hasSeenWelcome ? <Route path="*" element={<WelcomePage onComplete={() => setHasSeenWelcome(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage mode="login" onGuestLogin={() => { setUser({ id: 'guest', name: 'Guest', email: '', avatar: 'https://ui-avatars.com/api/?name=Guest', userType: 'Student' }); setIsGuest(true); }} />} /> : 
           <>
              <Route path="/" element={<HomePage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} />} />
              <Route path="/menu" element={<MenuPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} />} />
              <Route path="/cart" element={<CartPage cart={cart} updateQty={(id, d) => setCart(prev => prev.map(i => i.id === id ? {...i, quantity: Math.max(0, i.quantity+d)} : i).filter(i => i.quantity > 0))} clearCart={() => setCart([])} placeOrder={placeOrder} />} />
              <Route path="/profile" element={<ProfilePage user={user} onLogout={() => setUser(null)} />} />
              <Route path="/orders" element={<OrdersPage orders={orders} />} />
              <Route path="/orders/:id" element={<OrderDetailsPage orders={orders} />} />
              <Route path="/stalls/:id" element={<StallDetailsPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} user={user} />} />
              <Route path="/food/:id" element={<FoodDetailsPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} user={user} />} />
           </>}
        </Routes>
      </AnimatePresence>
      {user && <BottomNav cartCount={cart.length} />}
      {user && <ChatBot menuItems={menuItems} stalls={stalls} />}
    </div>
  );
};

