const OrderDetailsPage: React.FC<{ orders: Order[] }> = ({ orders }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [order, setOrder] = useState<Order | null>(orders.find(o => o.id === id) || null);
  const [loading, setLoading] = useState(!order);

  useEffect(() => {
    const fetchOrder = async () => {
      setLoading(true);
      try {
        const { data, error } = await supabase.from('orders').select('*').eq('id', id).single();
        if (data) setOrder(mapOrder(data));
        else {
          const mock = orders.find(o => o.id === id);
          if (mock) setOrder(mock);
        }
      } catch (err) {
        console.error("Fetch order detail failed", err);
      } finally {
        setLoading(false);
      }
    };
    if (id) fetchOrder();
  }, [id, orders]);

  if (loading) return (
    <div className="h-screen flex items-center justify-center bg-white">
        <div className="flex flex-col items-center gap-4">
            <Loader className="animate-spin text-bupc-blue" size={40} />
