    <div className="p-10 text-center flex flex-col items-center justify-center h-screen gap-6">
        <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center text-red-500">
            <X size={40} />
        </div>
        <div>
            <h2 className="text-xl font-bold">Order Not Found</h2>
            <p className="text-gray-500 text-sm mt-1">We couldn't find the order you're looking for.</p>
        </div>
        <Button onClick={() => navigate('/orders')} variant="outline">Back to My Orders</Button>
    </div>
  );

  const stallName = order.items[0]?.stallName || "Campus Stall";

  return (
    <PageTransition>
      <div className="bg-gray-50 min-h-screen">
        <Header title={`Order Details`} backUrl="/orders" />
        <div className="p-4 space-y-4 max-w-md mx-auto">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col items-center"
          >
             <div className="flex items-center gap-2 mb-2">
                 <Store size={16} className="text-bupc-blue" />
                 <span className="text-sm font-bold text-gray-500 uppercase tracking-widest">{stallName}</span>
             </div>
             <h2 className="text-2xl font-black text-gray-900 mb-8">Order Tracker</h2>
             <OrderStatusStepper currentStatus={order.status} />
             <div className={`mt-8 w-full p-4 rounded-2xl flex items-center gap-3 ${
                 order.status === OrderStatus.READY ? 'bg-green-50 text-green-700' : 'bg-blue-50 text-bupc-blue'
             }`}>
