                 <span className="text-sm font-bold">
                     {order.status === OrderStatus.READY ? "Ready for pickup!" : `Currently: ${order.status}`}
                 </span>
             </div>
          </motion.div>

          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
