// --- Helper Functions to Map DB Types to App Types ---
const mapStall = (dbStall: any): Stall => ({
    id: String(dbStall.id || ''),
    name: dbStall.name || 'Unnamed Stall',
    image: dbStall.image || dbStall.image_url || 'https://images.unsplash.com/photo-1554118811-1e0d58224f24?auto=format&fit=crop&w=800&q=80',
    description: dbStall.description || '',
    phone: dbStall.phone || '',
    schedule: dbStall.schedule || 'Mon-Fri',
    openTime: dbStall.open_time || dbStall.openTime || '8:00 AM',
    closeTime: dbStall.close_time || dbStall.closeTime || '5:00 PM',
    location: dbStall.location || 'BUPC Canteen'
});

const mapMenuItem = (dbItem: any, stalls: Stall[]): MenuItem => {
    const sId = String(dbItem.stall_id || dbItem.stallId || '');
    return {
        id: String(dbItem.id || ''),
        name: dbItem.name || 'Unnamed Item',
        description: dbItem.description || '',
        price: Number(dbItem.price) || 0,
        category: dbItem.category || 'Meals',
        image: dbItem.image || dbItem.image_url || 'https://images.unsplash.com/photo-1563379926898-05f4575a45d8?auto=format&fit=crop&w=800&q=80',
        stallId: sId,
        stallName: stalls.find(s => s.id === sId)?.name || dbItem.stall_name || 'Unknown Stall',
        rating: Number(dbItem.rating) || 5.0,
        calories: dbItem.calories,
        isPopular: dbItem.is_popular ?? dbItem.isPopular ?? false,
        isSpicy: dbItem.is_spicy ?? dbItem.isSpicy ?? false,
        isVeg: dbItem.is_veg ?? dbItem.isVeg ?? false
    };
};

const mapOrder = (dbOrder: any): Order => ({
    id: String(dbOrder.id || ''),
    items: Array.isArray(dbOrder.items) ? dbOrder.items : [],
    subtotal: (dbOrder.items || []).reduce((acc: number, item: any) => acc + (Number(item.price) * Number(item.quantity || 1)), 0),
    fee: 15,
    total: Number(dbOrder.total) || 0,
    status: (dbOrder.status as OrderStatus) || OrderStatus.PENDING,
    date: new Date(dbOrder.created_at || Date.now()),
    paymentMethod: (dbOrder.payment_method || dbOrder.paymentMethod || 'Cash') as PaymentMethod
});

const mapReview = (dbReview: any): Review => ({
    id: String(dbReview.id),
    userId: dbReview.user_id,
    userName: dbReview.user_name || 'Anonymous User',
    targetId: String(dbReview.target_id),
    targetType: dbReview.target_type as 'stall' | 'menu_item',
    rating: Number(dbReview.rating),
    comment: dbReview.comment,
    date: new Date(dbReview.created_at)
});

