const FoodDetailsPage: React.FC<{ addToCart: (i: MenuItem) => void, menuItems: MenuItem[], user: UserType | any }> = ({ addToCart, menuItems, user }) => {
  const { id } = useParams();
  const item = menuItems.find(i => i.id === id);
  const navigate = useNavigate();
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loadingReviews, setLoadingReviews] = useState(true);
  const [isReviewModalOpen, setIsReviewModalOpen] = useState(false);
  const [newRating, setNewRating] = useState(5);
  const [newComment, setNewComment] = useState('');
  const [submittingReview, setSubmittingReview] = useState(false);

  useEffect(() => {
    if (id) {
        setLoadingReviews(true);
        supabase.from('reviews').select('*').eq('target_id', id).eq('target_type', 'menu_item').order('created_at', { ascending: false })
            .then(({ data, error }) => {
                if (data) setReviews(data.map(mapReview));
                else setReviews(MOCK_REVIEWS.filter(r => r.targetId === id) as Review[]);
                setLoadingReviews(false);
            });
    }
  }, [id]);

  const handleSubmitReview = async () => {
    if (!user || !id) return;
    setSubmittingReview(true);
    const reviewData = {
        user_id: user.id,
        user_name: user.name,
        target_id: id,
        target_type: 'menu_item',
        rating: newRating,
        comment: newComment,
        created_at: new Date().toISOString()
    };

    try {
        const { data, error } = await supabase.from('reviews').insert([reviewData]).select();
        if (data) setReviews(prev => [mapReview(data[0]), ...prev]);
        setIsReviewModalOpen(false);
        setNewComment('');
    } catch (err) {
        console.error("Review failed", err);
    } finally {
        setSubmittingReview(false);
    }
  };

  if (!item) return <div className="p-10 text-center">Food not found</div>;

  return (
    <PageTransition>
      <div className="relative aspect-square max-w-md mx-auto"><img src={item.image} className="w-full h-full object-cover shadow-2xl" /><button onClick={() => navigate(-1)} className="absolute top-4 left-4 w-10 h-10 bg-black/20 backdrop-blur-md rounded-full flex items-center justify-center text-white transition-all hover:bg-black/40"><ChevronLeft size={24} /></button></div>
      <div className="p-6 space-y-6 bg-white/80 backdrop-blur-xl -mt-8 rounded-t-[3rem] relative z-10 shadow-[0_-20px_50px_rgba(0,0,0,0.1)] max-w-md mx-auto min-h-[60vh]">
        <div className="flex justify-between items-start">
            <div>
                <h1 className="text-2xl font-black text-gray-900 tracking-tight">{item.name}</h1>
                <p className="text-sm font-bold text-bupc-blue uppercase tracking-widest">{item.stallName}</p>
            </div>
            <div className="text-2xl font-black text-bupc-orange">₱{item.price}</div>
        </div>

        <div className="flex items-center gap-4 py-2 border-y border-gray-100">
            <div className="flex items-center gap-1">
                <StarRating rating={Math.round(item.rating)} size={14} />
                <span className="text-xs font-black text-gray-900 ml-1">{item.rating}</span>
            </div>
            <div className="w-px h-3 bg-gray-200" />
            <div className="flex items-center gap-1 text-gray-500">
                <MessageSquareQuote size={14} />
                <span className="text-xs font-bold">{reviews.length} Reviews</span>
            </div>
        </div>

        <p className="text-gray-500 leading-relaxed text-sm">{item.description}</p>

        <div className="flex gap-2">
            {item.isPopular && <Badge active className="text-[10px] bg-yellow-400 border-yellow-400">Best Seller</Badge>}
            {item.isSpicy && <Badge active className="text-[10px] bg-red-500 border-red-500 flex items-center gap-1"><Flame size={10} /> Spicy</Badge>}
            {item.isVeg && <Badge active className="text-[10px] bg-green-500 border-green-500 flex items-center gap-1"><Leaf size={10} /> Veggie</Badge>}
        </div>

        <Button className="w-full h-14 rounded-2xl mt-4 shadow-xl shadow-orange-100" onClick={() => { addToCart(item); navigate('/cart'); }}>Add to Cart • ₱{item.price}</Button>

        {/* Reviews Section */}
        <div className="pt-8 space-y-6">
            <div className="flex justify-between items-center">
                <h3 className="font-black text-gray-900 uppercase tracking-tight text-sm">Customer Reviews</h3>
                <button onClick={() => setIsReviewModalOpen(true)} className="text-xs font-bold text-bupc-blue uppercase underline">Write Review</button>
            </div>

            <div className="space-y-4">
                {loadingReviews ? (
                    <div className="flex justify-center py-4"><Loader className="animate-spin text-gray-200" /></div>
                ) : reviews.length === 0 ? (
                    <div className="text-center py-8 bg-gray-50/50 rounded-2xl border border-dashed border-gray-200 text-gray-400 text-xs font-medium uppercase">No reviews yet. Be the first!</div>
                ) : (
                    reviews.map(review => (
                        <div key={review.id} className="bg-white/50 p-4 rounded-2xl border border-gray-100 shadow-sm">
                            <div className="flex justify-between items-start mb-2">
                                <div className="flex items-center gap-2">
                                    <div className="w-8 h-8 rounded-full bg-blue-50 flex items-center justify-center text-[10px] font-bold text-bupc-blue uppercase">{review.userName.charAt(0)}</div>
                                    <div>
                                        <p className="text-xs font-black text-gray-900 leading-none">{review.userName}</p>
                                        <p className="text-[10px] text-gray-400 mt-1">{review.date.toLocaleDateString()}</p>
                                    </div>
                                </div>
                                <StarRating rating={review.rating} size={10} />
                            </div>
                            <p className="text-xs text-gray-600 leading-relaxed italic">"{review.comment}"</p>
                        </div>
                    ))
                )}
            </div>
        </div>

        <Modal isOpen={isReviewModalOpen} onClose={() => setIsReviewModalOpen(false)} title="Write a Review">
            <div className="space-y-4">
                <div className="flex flex-col items-center gap-2 mb-4">
                    <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Rate this meal</p>
                    <StarRating rating={newRating} size={32} interactive onChange={setNewRating} />
                </div>
                <textarea 
                    value={newComment} 
                    onChange={e => setNewComment(e.target.value)} 
                    placeholder="Tell us what you think about this dish..." 
                    className="w-full h-32 bg-gray-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-bupc-blue outline-none transition-all"
                />
                <Button 
                    className="w-full h-12 rounded-xl" 
                    onClick={handleSubmitReview} 
                    disabled={!newComment.trim() || submittingReview}
                >
                    {submittingReview ? <Loader className="animate-spin" size={20} /> : 'Submit Review'}
                </Button>
            </div>
        </Modal>
      </div>
    </PageTransition>
  );
};

