const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [hasSeenWelcome, setHasSeenWelcome] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [authLoading, setAuthLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [stallsRes, itemsRes] = await Promise.all([
          supabase.from('stalls').select('*'),
          supabase.from('menu_items').select('*')
        ]);

        const dbStalls = (stallsRes.data && stallsRes.data.length > 0) 
            ? stallsRes.data.map(mapStall) 
            : STALLS;
        setStalls(dbStalls);

        const dbItems = (itemsRes.data && itemsRes.data.length > 0) 
            ? itemsRes.data.map(i => mapMenuItem(i, dbStalls)) 
            : MENU_ITEMS;
        setMenuItems(dbItems);
      } catch (err) {
        console.error("Critical error fetching Supabase data:", err);
        setStalls(STALLS);
        setMenuItems(MENU_ITEMS);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        supabase.from('profiles').select('*').eq('id', session.user.id).single().then(({ data }) => {
          if (data) {
            setUser({ id: data.id, name: data.name, email: data.email, avatar: data.avatar, userType: data.user_type });
            supabase.from('orders').select('*').eq('user_id', data.id).order('created_at', { ascending: false }).then(({ data: o }) => o && setOrders(o.map(mapOrder)));
          }
          setAuthLoading(false);
        });
      } else setAuthLoading(false);
    });
  }, []);

  const placeOrder = async (items: CartItem[], method: PaymentMethod) => {
    if (!user) return;
    const total = items.reduce((s, i) => s + (i.price * i.quantity), 0) + 15;
    const tempId = `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;
    const newOrder: Order = { id: tempId, items, subtotal: total-15, fee: 15, total, status: OrderStatus.PENDING, date: new Date(), paymentMethod: method };

    // Optimistically update UI
    setOrders(prev => [newOrder, ...prev]);

    if (user.id === 'guest') return;

    try {
        const { data, error } = await supabase.from('orders').insert([{ 
            user_id: user.id, 
            items: items, 
            total: total, 
            payment_method: method, 
            status: 'Pending' 
        }]).select().single();

        if (error) {
            console.error("Order Insert Error Detail:", error);
            throw new Error(error.message || JSON.stringify(error));
        }
        if (data) {
            setOrders(prev => prev.map(o => o.id === tempId ? mapOrder(data) : o));
        }
    } catch (err: any) {
        const readableError = err?.message || JSON.stringify(err);
        console.error("Caught error in placeOrder:", readableError);
        alert(`Order placement failed: ${readableError}`);
    }
  };

  if (authLoading) return <div className="h-screen flex items-center justify-center font-black text-bupc-blue animate-pulse">DineTime BUPC...</div>;

  return (
    <div className="min-h-screen max-w-md mx-auto relative font-sans text-gray-900 overflow-x-hidden 
      bg-[#F8FAFC]
      [background-image:radial-gradient(#e5e7eb_1px,transparent_1px),radial-gradient(circle_at_0%_0%,rgba(0,51,160,0.03)_0%,transparent_50%),radial-gradient(circle_at_100%_100%,rgba(255,103,31,0.03)_0%,transparent_50%)] 
      [background-size:24px_24px,100%_100%,100%_100%]
      shadow-[0_0_100px_rgba(0,0,0,0.1)]">

      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!hasSeenWelcome ? <Route path="*" element={<WelcomePage onComplete={() => setHasSeenWelcome(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage onGuestLogin={() => setUser({ id: 'guest', name: 'Guest', avatar: 'https://ui-avatars.com/api/?name=Guest' })} />} /> : 
           <>
              <Route path="/" element={<HomePage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} />} />
              <Route path="/menu" element={<MenuPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} />} />
              <Route path="/cart" element={<CartPage cart={cart} updateQty={(id, d) => setCart(prev => prev.map(i => i.id === id ? {...i, quantity: Math.max(0, i.quantity+d)} : i).filter(i => i.quantity > 0))} clearCart={() => setCart([])} placeOrder={placeOrder} />} />
              <Route path="/profile" element={<ProfilePage user={user} onLogout={() => setUser(null)} />} />
              <Route path="/orders" element={<OrdersPage orders={orders} />} />
              <Route path="/orders/:id" element={<OrderDetailsPage orders={orders} />} />
              <Route path="/stalls/:id" element={<StallDetailsPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} />} />
              <Route path="/food/:id" element={<FoodDetailsPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} user={user} />} />
           </>}
        </Routes>
      </AnimatePresence>
      {user && <BottomNav cartCount={cart.length} />}
      {user && <ChatBot menuItems={menuItems} stalls={stalls} />}
    </div>
  );
};

const App: React.FC = () => (<HashRouter><AppContent /></HashRouter>);
export default App;

