const MenuPage: React.FC<{ addToCart: (i: MenuItem) => void, menuItems: MenuItem[] }> = ({ addToCart, menuItems }) => {
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [filters, setFilters] = useState({ maxPrice: 200, minRating: 0, spicyOnly: false, vegOnly: false });
  const navigate = useNavigate();

  const filteredItems = menuItems.filter(item => {
    const matchesCat = selectedCategory === 'All' || item.category === selectedCategory;
    const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || item.stallName.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesPrice = item.price <= filters.maxPrice;
    const matchesRating = item.rating >= filters.minRating;
    const matchesSpicy = !filters.spicyOnly || item.isSpicy;
    const matchesVeg = !filters.vegOnly || item.isVeg;
    return matchesCat && matchesSearch && matchesPrice && matchesRating && matchesSpicy && matchesVeg;
  });

  return (
    <PageTransition>
      <Header title="Menu" rightAction={<button onClick={() => setIsFilterOpen(true)} className="p-3 bg-white/80 border border-gray-100 rounded-2xl shadow-sm text-gray-600"><Filter size={20} /></button>} />
      <div className="p-4 space-y-6 max-w-md mx-auto">
        <div className="relative group">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300 group-focus-within:text-bupc-blue transition-colors" size={20} />
          <input type="text" placeholder="Search for food..." className="w-full bg-white/80 backdrop-blur-md border border-gray-100 rounded-[1.5rem] pl-12 pr-4 h-14 text-sm font-medium focus:ring-2 focus:ring-bupc-blue focus:bg-white outline-none transition-all shadow-sm" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
        </div>

        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar -mx-4 px-4">{CATEGORIES.map(cat => (<Badge key={cat} active={selectedCategory === cat} onClick={() => setSelectedCategory(cat)}>{cat}</Badge>))}</div>

        <div className="grid grid-cols-2 gap-4">
          {filteredItems.length === 0 ? (
             <div className="col-span-2 text-center py-20 text-gray-400 font-bold uppercase text-xs tracking-widest">No matching items found</div>
          ) : filteredItems.map(item => (<ProductCard key={item.id} item={item} onAdd={addToCart} onClick={() => navigate(`/food/${item.id}`)} />))}
        </div>
      </div>

      <Modal isOpen={isFilterOpen} onClose={() => setIsFilterOpen(false)} title="Filters">
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-3">Max Price: ₱{filters.maxPrice}</p>
              <input type="range" min="20" max="300" step="10" value={filters.maxPrice} onChange={e => setFilters(f => ({...f, maxPrice: Number(e.target.value)}))} className="w-full accent-bupc-blue" />
            </div>
            <div>
              <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-3">Dietary</p>
              <div className="flex gap-2">
                <Badge active={filters.spicyOnly} onClick={() => setFilters(f => ({...f, spicyOnly: !f.spicyOnly}))}>Spicy Only</Badge>
                <Badge active={filters.vegOnly} onClick={() => setFilters(f => ({...f, vegOnly: !f.vegOnly}))}>Veggie Only</Badge>
              </div>
            </div>
            <Button className="w-full h-12 rounded-xl" onClick={() => setIsFilterOpen(false)}>Apply Filters</Button>
          </div>
      </Modal>
    </PageTransition>
  );
};

