// --- Main App ---

const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    Promise.all([supabase.from('stalls').select('*'), supabase.from('menu_items').select('*')])
      .then(([s, m]) => {
        const dbStalls = s.data && s.data.length ? s.data.map(mapStall) : STALLS;
        const dbItems = m.data && m.data.length ? m.data.map(i => mapMenuItem(i, dbStalls)) : MENU_ITEMS;
        setStalls(dbStalls);
        setMenuItems(dbItems);
        setLoading(false);
      });
  }, []);

  if (loading) return <div className="h-screen flex flex-col items-center justify-center bg-white"><Loader className="animate-spin text-bupc-blue mb-4" size={40} /><p className="font-black text-xs uppercase tracking-widest text-bupc-blue">Fueling Oragons...</p></div>;

  return (
    <div className="min-h-screen max-w-md mx-auto relative font-sans text-gray-900 overflow-x-hidden bg-[#F8FAFC] 
      [background-image:radial-gradient(#e5e7eb_1px,transparent_1px),radial-gradient(circle_at_0%_0%,rgba(0,51,160,0.04)_0%,transparent_50%),radial-gradient(circle_at_100%_100%,rgba(255,103,31,0.04)_0%,transparent_50%)] 
      [background-size:24px_24px,100%_100%,100%_100%] shadow-2xl">
      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!onboardingComplete ? <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage onAuth={setUser} />} /> : 
           <>
              <Route path="/" element={<HomePage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} stalls={stalls} menuItems={menuItems} />} />
              <Route path="/menu" element={<MenuPage addToCart={i => setCart(prev => [...prev, {...i, quantity: 1}])} menuItems={menuItems} />} />
              <Route path="/notifications" element={<NotificationsPage />} />
              <Route path="/profile" element={<ProfilePage user={user} onLogout={() => setUser(null)} />} />
              {/* Other routes as implemented previously... */}
           </>}
        </Routes>
      </AnimatePresence>
      {user && <BottomNav cartCount={cart.length} />}
      {user && <ChatBot menuItems={menuItems} stalls={stalls} />}
    </div>
  );
};

const App: React.FC = () => (<HashRouter><AppContent /></HashRouter>);
export default App;

