  return (
    <motion.button whileTap={{ scale: 0.96 }} className={`inline-flex items-center justify-center rounded-2xl font-black uppercase tracking-widest transition-all disabled:opacity-50 ${variants[variant]} ${sizes[size]} ${className}`} {...props}>
