// --- Bottom Navigation ---
const BottomNav: React.FC<{ cartCount: number }> = ({ cartCount }) => {
  const location = useLocation();
  const isActive = (path: string) => location.pathname === path || (path !== '/' && location.pathname.startsWith(path));
  const navItems = [
    { icon: Home, label: 'Home', path: '/' },
    { icon: UtensilsCrossed, label: 'Menu', path: '/menu' },
    { icon: ShoppingBag, label: 'Cart', path: '/cart', badge: cartCount },
    { icon: ClipboardList, label: 'Orders', path: '/orders' },
    { icon: User, label: 'Profile', path: '/profile' },
  ];
  if (['/login', '/signup', '/welcome'].includes(location.pathname)) return null;
  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-3xl border-t border-gray-100/50 pb-safe z-50 max-w-md mx-auto shadow-[0_-15px_50px_rgba(0,0,0,0.08)]">
      <div className="flex justify-around items-center h-20 px-2">
        {navItems.map((item) => (
          <Link key={item.label} to={item.path} className={`flex flex-col items-center justify-center w-full h-full space-y-1.5 transition-all ${isActive(item.path) ? 'text-bupc-blue' : 'text-gray-400'}`}>
            <motion.div whileTap={{ scale: 0.8 }} className="relative">
              <item.icon size={22} strokeWidth={isActive(item.path) ? 2.5 : 2} />
              {item.badge > 0 && (
                <span className="absolute -top-2 -right-2 bg-bupc-orange text-white text-[9px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white shadow-lg">{item.badge}</span>
              )}
            </motion.div>
            <span className="text-[9px] font-black uppercase tracking-widest leading-none">{item.label}</span>
          </Link>
        ))}
      </div>
    </div>
  );
};

// --- Onboarding Slide Component ---
const OnboardingSlide: React.FC<{ title: string; desc: string; icon: any; step: number }> = ({ title, desc, icon: Icon, step }) => {
  const shapes = [
    { color: 'bg-blue-500/10', size: 'w-64 h-64', pos: '-top-10 -left-10' },
    { color: 'bg-orange-500/10', size: 'w-48 h-48', pos: '-bottom-10 -right-10' },
    { color: 'bg-indigo-500/5', size: 'w-80 h-80', pos: 'top-1/4 -right-20' },
  ];
  return (
    <div className="relative w-full h-full flex flex-col items-center justify-center overflow-hidden">
      {shapes.map((s, i) => (
        <motion.div 
          key={i} 
          animate={{ scale: [1, 1.1, 1], rotate: [0, 10, 0] }} 
          transition={{ duration: 10, repeat: Infinity, delay: i * 2 }}
          className={`absolute ${s.color} ${s.size} ${s.pos} rounded-full blur-3xl`}
        />
      ))}
      <motion.div 
        initial={{ scale: 0, rotate: -10 }} 
        animate={{ scale: 1, rotate: 0 }} 
        className="w-44 h-44 bg-white rounded-[4rem] shadow-2xl flex items-center justify-center mb-12 border border-gray-50 relative z-10"
      >
        <div className="absolute inset-4 bg-gray-50 rounded-[3rem] animate-pulse" />
        <Icon size={72} className="text-bupc-blue relative z-20" />
      </motion.div>
      <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tighter z-10">{title}</h2>
      <p className="text-gray-500 text-lg font-medium leading-relaxed max-w-xs z-10">{desc}</p>
    </div>
  );
};

const OnboardingPage: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [step, setStep] = useState(0);
  const slides = [
    { title: "Smart Dining", desc: "Our AI 'DineBot' helps you pick the perfect meal in seconds.", icon: Sparkles },
    { title: "Skip the Wait", desc: "Order from your classroom and grab it when it's ready.", icon: Zap },
    { title: "Campus Favorites", desc: "Support local stalls and enjoy authentic BUPC flavor.", icon: Heart }
  ];
  return (
    <div className="h-screen bg-white flex flex-col items-center justify-between p-8 text-center">
      <div className="flex-1 w-full">
        <AnimatePresence mode="wait">
          <motion.div key={step} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 1.05 }} className="w-full h-full">
            <OnboardingSlide {...slides[step]} step={step} />
          </motion.div>
        </AnimatePresence>
      </div>
      <div className="w-full space-y-8 pb-8">
        <div className="flex justify-center gap-2.5">
          {slides.map((_, i) => (
            <motion.div key={i} animate={{ width: i === step ? 32 : 10 }} className={`h-2 rounded-full transition-all ${i === step ? 'bg-bupc-blue' : 'bg-gray-100'}`} />
          ))}
        </div>
        <Button className="w-full h-18 rounded-[2.5rem] text-lg shadow-2xl" onClick={() => step < 2 ? setStep(s => s + 1) : onComplete()}>
          {step < 2 ? 'Next Chapter' : 'Start Ordering'}
        </Button>
      </div>
    </div>
  );
};

