// --- CartPage ---
const CartPage: React.FC<{ cart: CartItem[], updateQty: (id: string, d: number) => void, clearCart: () => void, placeOrder: (items: CartItem[], method: PaymentMethod) => void }> = ({ cart, updateQty, clearCart, placeOrder }) => {
  const [method, setMethod] = useState<PaymentMethod>('GCash');
  const navigate = useNavigate();
  const subtotal = cart.reduce((s, i) => s + (i.price * i.quantity), 0);
  const total = subtotal + 15;
  const handlePlace = () => { placeOrder(cart, method); clearCart(); navigate('/orders'); };

  if (cart.length === 0) return (
    <PageWrapper>
      <Header title="Cart" />
      <div className="flex flex-col items-center justify-center pt-24 px-10 text-center">
        <div className="w-32 h-32 bg-gray-100 rounded-[3rem] flex items-center justify-center text-gray-300 mb-8">
          <ShoppingBag size={48} />
        </div>
        <h3 className="text-2xl font-black text-gray-900 tracking-tight">Your cart is empty</h3>
        <p className="text-gray-400 font-medium mt-2">Looks like you haven't added anything to your cart yet.</p>
        <Button className="mt-10 px-10 rounded-2xl h-14" onClick={() => navigate('/menu')}>Start Exploring</Button>
      </div>
    </PageWrapper>
  );

  return (
    <PageWrapper>
      <Header title="My Cart" />
      <div className="px-5 space-y-8 mt-6 max-w-md mx-auto">
        <div className="space-y-4">
          {cart.map(item => (
            <motion.div layout key={item.id} className="bg-white/70 backdrop-blur-md rounded-[2.5rem] border border-white p-4 shadow-sm flex items-center gap-5">
              <img src={item.image} className="w-20 h-20 rounded-2xl object-cover" />
              <div className="flex-1">
                <h4 className="font-black text-gray-900 text-sm">{item.name}</h4>
                <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-2">{item.stallName}</p>
                <div className="flex items-center justify-between">
                  <span className="font-black text-bupc-blue">₱{item.price * item.quantity}</span>
                  <div className="flex items-center gap-3 bg-gray-50/50 p-1 rounded-xl">
                    <button onClick={() => updateQty(item.id, -1)} className="w-8 h-8 rounded-lg bg-white flex items-center justify-center text-gray-400 shadow-sm">-</button>
                    <span className="font-black text-xs min-w-[12px] text-center">{item.quantity}</span>
                    <button onClick={() => updateQty(item.id, 1)} className="w-8 h-8 rounded-lg bg-bupc-blue text-white flex items-center justify-center shadow-md">+</button>
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        <div className="bg-white/80 backdrop-blur-md rounded-[2.5rem] border border-white p-8 shadow-sm space-y-5">
          <h3 className="text-[10px] font-black uppercase tracking-widest text-gray-400">Order Summary</h3>
          <div className="space-y-3">
            <div className="flex justify-between text-sm font-bold text-gray-500"><span>Subtotal</span><span>₱{subtotal}</span></div>
            <div className="flex justify-between text-sm font-bold text-gray-500"><span>Delivery Fee</span><span>₱15</span></div>
            <div className="pt-4 border-t border-dashed border-gray-100 flex justify-between items-center">
              <span className="font-black text-gray-900 text-lg uppercase tracking-widest">Total</span>
              <span className="font-black text-bupc-orange text-3xl tracking-tighter">₱{total}</span>
            </div>
          </div>
          <div className="pt-4 space-y-4">
            <div className="grid grid-cols-3 gap-2">
              {['GCash', 'Cash', 'PayMaya'].map(m => (
                <button key={m} onClick={() => setMethod(m as PaymentMethod)} className={`py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border-2 transition-all ${method === m ? 'bg-bupc-blue/5 border-bupc-blue text-bupc-blue' : 'bg-transparent border-gray-50 text-gray-400'}`}>{m}</button>
              ))}
            </div>
            <Button className="w-full h-18 rounded-[2.5rem] text-lg shadow-xl" onClick={handlePlace}>Confirm Order</Button>
          </div>
        </div>
      </div>
    </PageWrapper>
  );
};

