// --- OrdersPage ---
const OrdersPage: React.FC<{ orders: Order[] }> = ({ orders }) => {
  const [tab, setTab] = useState<'active' | 'history'>('active');
  const filtered = orders.filter(o => tab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED);
  return (
    <PageWrapper>
      <Header title="My Orders" />
      <div className="px-5 mt-6 max-w-md mx-auto space-y-6">
        <div className="flex p-1.5 bg-gray-100 rounded-[2rem]">
          <button onClick={() => setTab('active')} className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-[1.5rem] transition-all ${tab === 'active' ? 'bg-white text-bupc-blue shadow-sm' : 'text-gray-400'}`}>Active</button>
          <button onClick={() => setTab('history')} className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-[1.5rem] transition-all ${tab === 'history' ? 'bg-white text-bupc-blue shadow-sm' : 'text-gray-400'}`}>History</button>
        </div>

        {filtered.length === 0 ? (
          <div className="text-center py-20">
            <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] mx-auto mb-6 flex items-center justify-center text-gray-200"><ClipboardList size={40} /></div>
            <p className="text-xs font-black text-gray-400 uppercase tracking-widest">No orders found</p>
          </div>
        ) : (
          <div className="space-y-4">
            {filtered.map(order => (
              <motion.div layout key={order.id} className="bg-white/80 backdrop-blur-md rounded-[2.5rem] p-6 border border-white shadow-sm">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h4 className="font-black text-gray-900">Order #{order.id.slice(-6)}</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">{order.items.length} Items • {order.date.toLocaleDateString()}</p>
                  </div>
                  <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${order.status === OrderStatus.READY ? 'bg-green-500 text-white shadow-lg shadow-green-100' : 'bg-blue-50 text-bupc-blue'}`}>
                    {order.status}
                  </div>
                </div>
                <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                  <span className="font-black text-bupc-blue text-lg">₱{order.total}</span>
                  <Link to={`/orders/${order.id}`} className="text-xs font-black text-gray-400 uppercase tracking-widest flex items-center gap-1">Details <ChevronRight size={14} /></Link>
                </div>
              </motion.div>
            ))}
          </div>
        )}
