// --- Helper Functions for Data Mapping ---
const mapStall = (s: any): Stall => ({
  id: s.id,
  name: s.name,
  image: s.image,
  description: s.description,
  phone: s.phone,
  schedule: s.schedule,
  openTime: s.open_time || s.openTime,
  closeTime: s.close_time || s.closeTime,
  location: s.location
});

const mapMenuItem = (i: any, stalls: Stall[]): MenuItem => {
  const stall = stalls.find(s => s.id === i.stall_id || s.id === i.stallId);
  return {
    id: i.id,
    name: i.name,
    description: i.description,
    price: i.price,
    category: i.category,
    image: i.image,
    stallName: stall?.name || i.stall_name || i.stallName || 'Unknown Stall',
    stallId: i.stall_id || i.stallId,
    rating: i.rating || 0,
    isPopular: i.is_popular || i.isPopular,
    isSpicy: i.is_spicy || i.isSpicy,
    isVeg: i.is_veg || i.isVeg
  };
};

// --- App Content & Routes ---
const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    Promise.all([supabase.from('stalls').select('*'), supabase.from('menu_items').select('*')])
      .then(([s, m]) => {
        const dbStalls = s.data?.length ? s.data.map(mapStall) : STALLS;
        const dbItems = m.data?.length ? m.data.map((i: any) => mapMenuItem(i, dbStalls)) : MENU_ITEMS;
        setStalls(dbStalls);
        setMenuItems(dbItems);
        setLoading(false);
      });
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.id === id ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i).filter(i => i.quantity > 0));
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = {
      id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`,
      items: [...items], 
      subtotal, 
      fee: 15, 
      total,
      status: OrderStatus.PENDING, 
      date: new Date(), 
      paymentMethod: method
    };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-white">
      <motion.div animate={{ scale: [1, 1.1, 1], rotate: [0, 360] }} transition={{ duration: 2, repeat: Infinity }} className="w-16 h-16 bg-bupc-blue rounded-[2rem] shadow-2xl shadow-blue-200 flex items-center justify-center text-white">
        <UtensilsCrossed size={32} />
      </motion.div>
      <p className="mt-8 font-black text-xs text-bupc-blue uppercase tracking-[0.3em] animate-pulse">Initializing DineTime</p>
    </div>
  );

  return (
    <div className="min-h-screen max-w-md mx-auto relative font-sans text-gray-900 overflow-x-hidden 
      bg-[#F8FAFC]
      [background-image:radial-gradient(circle_at_0%_0%,rgba(0,51,160,0.05)_0%,transparent_40%),radial-gradient(circle_at_100%_100%,rgba(255,103,31,0.05)_0%,transparent_40%),linear-gradient(to_bottom,transparent,rgba(0,0,0,0.02))] 
      shadow-2xl">
      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!onboardingComplete ? <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage onAuth={setUser} />} /> : 
           <>
              <Route path="/" element={<HomePage addToCart={addToCart} stalls={stalls} menuItems={menuItems} />} />
              <Route path="/menu" element={<MenuPage addToCart={addToCart} menuItems={menuItems} />} />
              <Route path="/cart" element={<CartPage cart={cart} updateQty={updateQty} clearCart={() => setCart([])} placeOrder={placeOrder} />} />
              <Route path="/orders" element={<OrdersPage orders={orders} />} />
              <Route path="/profile" element={<ProfilePage user={MOCK_USER} onLogout={() => setUser(null)} />} />
              <Route path="/food/:id" element={<FoodDetailsPage addToCart={addToCart} menuItems={menuItems} />} />
           </>}
        </Routes>
      </AnimatePresence>
      {user && <BottomNav cartCount={cart.length} />}
      {user && <ChatBot menuItems={menuItems} stalls={stalls} />}
    </div>
  );
};

const App: React.FC = () => (<HashRouter><AppContent /></HashRouter>);
export default App;

