    { icon: Home, label: 'Home', path: '/' },
    { icon: UtensilsCrossed, label: 'Menu', path: '/menu' },
    { icon: ShoppingBag, label: 'Cart', path: '/cart', badge: cartCount },
    { icon: ClipboardList, label: 'Orders', path: '/orders' },
    { icon: User, label: 'Profile', path: '/profile' },
  ];
  if (['/login', '/signup', '/welcome'].includes(location.pathname)) return null;
  return (
    <div className="fixed bottom-6 left-6 right-6 z-50 max-w-md mx-auto">
      <div className={`${THEME.surface} rounded-[3rem] h-20 px-4 flex items-center justify-around shadow-[0_20px_50px_rgba(0,0,0,0.5)] border border-white/20`}>
        {navItems.map((item) => (
          <Link key={item.label} to={item.path} className={`relative flex flex-col items-center gap-1 group`}>
            <motion.div whileTap={{ scale: 0.8 }} className={`${isActive(item.path) ? 'text-bupc-orange' : 'text-slate-400'} transition-colors`}>
              <item.icon size={24} strokeWidth={isActive(item.path) ? 2.5 : 2} />
              {item.badge > 0 && (
                <span className="absolute -top-2 -right-2 bg-bupc-blue text-white text-[10px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-[#1A1F2C]">{item.badge}</span>
              )}
            </motion.div>
            {isActive(item.path) && (
              <motion.div layoutId="nav-active" className="absolute -bottom-2 w-1 h-1 bg-bupc-orange rounded-full" />
            )}
          </Link>
        ))}
      </div>
    </div>
  );
};

