// --- Auth Page ---
const AuthPage: React.FC<{ onAuth: (user: any) => void }> = ({ onAuth }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ email: '', password: '', name: '' });
  const [error, setError] = useState('');

  const handleAuth = async () => {
    setLoading(true);
    setError('');
    try {
      if (isLogin) {
        const { data, error } = await supabase.auth.signInWithPassword({ email: form.email, password: form.password });
        if (error) throw error;
        onAuth({ ...MOCK_USER, email: data.user.email, id: data.user.id });
      } else {
        const { data, error } = await supabase.auth.signUp({ 
          email: form.email, 
          password: form.password,
          options: { data: { full_name: form.name } }
        });
        if (error) throw error;
        onAuth({ ...MOCK_USER, name: form.name, email: data.user?.email, id: data.user?.id });
      }
    } catch (e: any) {
      setError(e.message || "Authentication failed. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen ${THEME.bg} flex flex-col p-8 justify-center`}>
      <motion.div initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className={`${THEME.surface} rounded-[3.5rem] p-10 shadow-3xl`}>
        <div className="w-20 h-20 bg-bupc-orange rounded-3xl mb-8 flex items-center justify-center text-white shadow-2xl">
          <UtensilsCrossed size={40} />
        </div>
        <h2 className="text-3xl font-black text-white mb-2 tracking-tighter">{isLogin ? 'Welcome Back' : 'Create Account'}</h2>
        <p className="text-slate-400 text-sm mb-8">Join the BUPC food revolution today.</p>

        {error && <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-xs font-bold rounded-2xl">{error}</div>}

        <div className="space-y-4">
          {!isLogin && <Input label="Full Name" placeholder="Juan Dela Cruz" value={form.name} onChange={(e:any) => setForm({...form, name: e.target.value})} />}
          <Input label="Student Email" placeholder="juan@bupc.edu.ph" value={form.email} onChange={(e:any) => setForm({...form, email: e.target.value})} />
          <Input label="Password" type="password" placeholder="••••••••" value={form.password} onChange={(e:any) => setForm({...form, password: e.target.value})} />

          <Button className="w-full h-16 rounded-[2rem] mt-4" onClick={handleAuth} disabled={loading}>
            {loading ? <Loader className="animate-spin" /> : isLogin ? 'Sign In' : 'Sign Up'}
          </Button>

          <button onClick={() => setIsLogin(!isLogin)} className="w-full text-center py-4 text-[10px] font-black uppercase text-slate-400 tracking-widest">
            {isLogin ? "Don't have an account? Sign Up" : "Already have an account? Sign In"}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

