const MenuPage: React.FC<{ addToCart: (i: MenuItem) => void, menuItems: MenuItem[] }> = ({ addToCart, menuItems }) => {
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [filters, setFilters] = useState({ maxPrice: 200, isSpicy: false, isPopular: false });
  const navigate = useNavigate();

  const filteredItems = menuItems.filter(item => {
    const matchesCat = selectedCategory === 'All' || item.category === selectedCategory;
    const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesPrice = item.price <= filters.maxPrice;
    const matchesSpicy = !filters.isSpicy || item.isSpicy;
    const matchesPopular = !filters.isPopular || item.isPopular;
    return matchesCat && matchesSearch && matchesPrice && matchesSpicy && matchesPopular;
  });

  return (
    <PageWrapper>
      <Header title="Browse Food" rightAction={
        <motion.button onClick={() => setIsFilterOpen(true)} className="p-3 bg-white/10 rounded-2xl text-white relative">
          <Filter size={22} />
          {(filters.isSpicy || filters.isPopular || filters.maxPrice < 200) && (
            <span className="absolute top-1 right-1 w-2 h-2 bg-bupc-orange rounded-full"></span>
          )}
        </motion.button>
      } />

      <div className="space-y-6">
        <div className="relative">
          <Input 
            placeholder="What's for lunch?" 
            className="pl-14 h-16 bg-white/10 border-white/5 text-white" 
            value={searchQuery}
            onChange={(e:any) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        </div>

        <div className="flex gap-2 overflow-x-auto no-scrollbar -mx-4 px-4 pb-2">
          {CATEGORIES.map(cat => (
            <Badge key={cat} active={selectedCategory === cat} onClick={() => setSelectedCategory(cat)}>{cat}</Badge>
          ))}
        </div>

        <div className="grid grid-cols-2 gap-4">
          {filteredItems.map(item => <ProductCard key={item.id} item={item} onAdd={addToCart} onClick={() => navigate(`/food/${item.id}`)} />)}
          {filteredItems.length === 0 && <p className="col-span-2 text-center text-slate-500 py-20 font-black uppercase tracking-widest text-[10px]">No results found</p>}
        </div>
      </div>

      <Modal isOpen={isFilterOpen} onClose={() => setIsFilterOpen(false)} title="Search Filters">
        <div className="space-y-6">
          <div>
            <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-3 block">Max Price: ₱{filters.maxPrice}</label>
            <input type="range" min="20" max="300" step="5" value={filters.maxPrice} onChange={e => setFilters({...filters, maxPrice: Number(e.target.value)})} className="w-full accent-bupc-orange" />
          </div>
          <div className="flex gap-2">
            <Badge active={filters.isSpicy} onClick={() => setFilters({...filters, isSpicy: !filters.isSpicy})}>🔥 Spicy Only</Badge>
            <Badge active={filters.isPopular} onClick={() => setFilters({...filters, isPopular: !filters.isPopular})}>⭐ Popular</Badge>
          </div>
          <Button className="w-full h-14 rounded-2xl" onClick={() => setIsFilterOpen(false)}>Apply Filters</Button>
        </div>
      </Modal>
    </PageWrapper>
  );
};

// --- App Root ---
const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();

  useEffect(() => {
    Promise.all([supabase.from('stalls').select('*'), supabase.from('menu_items').select('*')])
      .then(([s, m]) => {
        const dbStalls = s.data?.length ? s.data.map(mapStall) : STALLS;
        const dbItems = m.data?.length ? m.data.map((i: any) => mapMenuItem(i, dbStalls)) : MENU_ITEMS;
        setStalls(dbStalls);
        setMenuItems(dbItems);
        setLoading(false);
      });
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = {
      id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`,
      items: [...items], subtotal, fee: 15, total,
      status: OrderStatus.PENDING, date: new Date(), paymentMethod: method
    };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex flex-col items-center justify-center`}>
      <motion.div animate={{ rotate: 360 }} transition={{ duration: 2, repeat: Infinity, ease: "linear" }} className="w-16 h-16 bg-bupc-orange rounded-3xl flex items-center justify-center text-white shadow-2xl">
        <UtensilsCrossed size={32} />
      </motion.div>
    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white selection:bg-bupc-orange/30 overflow-x-hidden`}>
      <div className="fixed top-[-10%] left-[-10%] w-[50%] h-[50%] bg-bupc-blue/10 blur-[150px] rounded-full" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-bupc-orange/10 blur-[150px] rounded-full" />

      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!onboardingComplete ? <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage onAuth={setUser} />} /> : 
           <>
              <Route path="/" element={
                <PageWrapper>
                  <Header showLocation />
                  <div className="space-y-12">
                    <motion.div className={`${THEME.surface} p-10 rounded-[3.5rem] shadow-3xl relative overflow-hidden group`}>
                      <div className="relative z-10">
                        <h1 className="text-3xl font-black mb-1 tracking-tighter">Stay Oragon, {user.name.split(' ')[0]}!</h1>
                        <p className="text-slate-400 text-sm mb-8 font-medium">BUPC's best meals are ready for you.</p>
                        <Button size="lg" className="rounded-2xl h-14" onClick={() => (document.querySelector('a[href="#/menu"]') as any)?.click()}>Explore Menu</Button>
                      </div>
                      <Sparkles className="absolute -right-6 -bottom-6 text-white/5 group-hover:text-white/10 transition-colors" size={240} />
                    </motion.div>

                    <div>
                      <div className="flex justify-between items-center mb-6 px-4">
                        <h3 className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em]">Featured Stalls</h3>
                        <ChevronRight size={18} className="text-slate-700" />
                      </div>
                      <div className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
