const mapStall = (s: any): Stall => ({
  id: String(s.id),
  name: s.name,
  image: s.image_url || s.image,
  description: s.description,
  phone: s.phone,
  schedule: s.schedule,
  openTime: s.open_time,
  closeTime: s.close_time,
  location: s.location
});

const mapMenuItem = (i: any, stalls: Stall[]): MenuItem => {
  const stall = stalls.find(s => s.id === String(i.stall_id));
  return {
    id: String(i.id),
    name: i.name,
    description: i.description,
    price: i.price,
    category: i.category,
    image: i.image_url || i.image,
    stallName: stall?.name || 'Unknown Stall',
    stallId: String(i.stall_id),
    rating: i.rating || 5,
    isPopular: i.is_popular,
    isSpicy: i.is_spicy,
    isVeg: i.is_veg
  };
};

