          <UtensilsCrossed size={40} />
        </div>
        <h2 className="text-4xl font-black text-white mb-2 tracking-tighter">{isLogin ? 'Hello!' : 'Join Us'}</h2>
        <p className="text-slate-400 text-sm mb-10">BUPC Intelligent Dining Hub.</p>

        {error && <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="mb-6 p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-xs font-black rounded-2xl">{error}</motion.div>}

        <div className="space-y-5">
          {!isLogin && <Input label="Full Name" placeholder="Juan Dela Cruz" value={form.name} onChange={(e:any) => setForm({...form, name: e.target.value})} />}
          <Input label="Student Email" placeholder="juan@bupc.edu.ph" value={form.email} onChange={(e:any) => setForm({...form, email: e.target.value})} />
          <Input label="Password" type="password" placeholder="••••••••" value={form.password} onChange={(e:any) => setForm({...form, password: e.target.value})} />

          <Button className="w-full h-18 rounded-[2rem] mt-4 text-lg" onClick={handleAuth} disabled={loading}>
            {loading ? <Loader className="animate-spin" /> : isLogin ? 'Sign In' : 'Sign Up'}
          </Button>

          <button onClick={() => setIsLogin(!isLogin)} className="w-full text-center py-4 text-[10px] font-black uppercase text-slate-500 tracking-widest hover:text-white transition-colors">
            {isLogin ? "Need an account? Create one" : "Already have an account? Sign In"}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

