const MenuPage: React.FC<{ addToCart: (i: MenuItem) => void, menuItems: MenuItem[] }> = ({ addToCart, menuItems }) => {
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [filters, setFilters] = useState({ maxPrice: 300, isSpicy: false, isPopular: false });
  const navigate = useNavigate();

  const filteredItems = menuItems.filter(item => {
    const matchesCat = selectedCategory === 'All' || item.category === selectedCategory;
    const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesPrice = item.price <= filters.maxPrice;
    const matchesSpicy = !filters.isSpicy || item.isSpicy;
    const matchesPopular = !filters.isPopular || item.isPopular;
    return matchesCat && matchesSearch && matchesPrice && matchesSpicy && matchesPopular;
  });

  return (
    <PageTransition>
      <Header title="Marketplace" rightAction={
        <motion.button whileTap={{ scale: 0.9 }} onClick={() => setIsFilterOpen(true)} className="p-3 bg-white/10 rounded-2xl text-white relative border border-white/5">
          <Filter size={22} />
          {(filters.isSpicy || filters.isPopular || filters.maxPrice < 300) && (
            <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-bupc-orange rounded-full shadow-[0_0_10px_rgba(255,103,31,1)]"></span>
          )}
        </motion.button>
      } />

      <div className="space-y-8">
        <div className="relative">
          <Input 
            placeholder="Search for cravings..." 
            className="pl-14 h-18 bg-white/10 border-white/10 text-white rounded-[1.5rem]" 
            value={searchQuery}
            onChange={(e:any) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={20} />
        </div>

        <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-4 px-4 pb-2">
          {CATEGORIES.map(cat => (
            <Badge key={cat} active={selectedCategory === cat} onClick={() => setSelectedCategory(cat)}>{cat}</Badge>
          ))}
        </div>

        <div className="grid grid-cols-2 gap-5 pb-10">
          {filteredItems.map(item => <ProductCard key={item.id} item={item} onAdd={addToCart} onClick={() => navigate(`/food/${item.id}`)} />)}
          {filteredItems.length === 0 && (
            <div className="col-span-2 text-center py-20">
              <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-700"><Search size={40} /></div>
              <p className="text-xs font-black uppercase text-slate-600 tracking-[0.3em]">No matching snacks</p>
            </div>
          )}
        </div>
      </div>

      <Modal isOpen={isFilterOpen} onClose={() => setIsFilterOpen(false)} title="Market Filters">
        <div className="space-y-8">
          <div>
            <div className="flex justify-between items-center mb-4">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Max Budget</label>
              <span className="text-sm font-black text-white">₱{filters.maxPrice}</span>
            </div>
            <input type="range" min="20" max="300" step="10" value={filters.maxPrice} onChange={e => setFilters({...filters, maxPrice: Number(e.target.value)})} className="w-full h-2 bg-white/10 rounded-full appearance-none accent-bupc-orange cursor-pointer" />
          </div>
          <div className="space-y-3">
             <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest block mb-1">Preferences</label>
             <div className="flex flex-wrap gap-2">
                <Badge active={filters.isSpicy} onClick={() => setFilters({...filters, isSpicy: !filters.isSpicy})}>🔥 Spicy REC</Badge>
                <Badge active={filters.isPopular} onClick={() => setFilters({...filters, isPopular: !filters.isPopular})}>⭐ Student Choice</Badge>
             </div>
          </div>
          <Button className="w-full h-18 rounded-[2rem] text-lg font-black" onClick={() => setIsFilterOpen(false)}>Save Preferences</Button>
        </div>
      </Modal>
    </PageTransition>
  );
};

