const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    Promise.all([supabase.from('stalls').select('*'), supabase.from('menu_items').select('*')])
      .then(([s, m]) => {
        const dbStalls = s.data?.length ? s.data.map(mapStall) : STALLS;
        const dbItems = m.data?.length ? m.data.map((i: any) => mapMenuItem(i, dbStalls)) : MENU_ITEMS;
        setStalls(dbStalls);
        setMenuItems(dbItems);
        setLoading(false);
      });
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = {
      id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`,
      items: [...items], subtotal, fee: 15, total,
      status: OrderStatus.PENDING, date: new Date(), paymentMethod: method
    };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex flex-col items-center justify-center`}>
      <motion.div animate={{ rotate: 360, scale: [1, 1.2, 1] }} transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }} className="w-20 h-20 bg-gradient-to-br from-bupc-orange to-red-600 rounded-[2.5rem] flex items-center justify-center text-white shadow-3xl">
        <UtensilsCrossed size={40} />
      </motion.div>
      <p className="mt-8 text-[10px] font-black uppercase text-slate-500 tracking-[0.4em] animate-pulse">Launching DineTime</p>
    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white selection:bg-bupc-orange/30 overflow-x-hidden relative`}>
      {/* Decorative Background Glows - Pointer events none is critical */}
      <div className="fixed top-[-20%] left-[-10%] w-[60%] h-[60%] bg-bupc-blue/10 blur-[150px] rounded-full pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-bupc-orange/10 blur-[150px] rounded-full pointer-events-none" />

      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!onboardingComplete ? <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage onAuth={setUser} />} /> : 
           <>
              <Route path="/" element={
                <PageTransition>
                  <Header showLocation />
                  <div className="space-y-12">
                    <motion.div 
                      whileHover={{ scale: 1.02 }}
                      className={`${THEME.surface} p-12 rounded-[4rem] shadow-3xl relative overflow-hidden group border-white/20`}
                    >
                      <div className="relative z-10">
                        <p className="text-[10px] font-black uppercase text-bupc-orange tracking-[0.2em] mb-4">Daily Discovery</p>
                        <h1 className="text-4xl font-black mb-1 tracking-tighter leading-none">Stay Oragon,</h1>
                        <h1 className="text-4xl font-black mb-8 tracking-tighter text-blue-400">{user.name.split(' ')[0]}!</h1>
                        <Button size="lg" className="rounded-[1.5rem] h-14 font-black" onClick={() => navigate('/menu')}>Explore All</Button>
                      </div>
                      <Sparkles className="absolute -right-10 -bottom-10 text-white/5 rotate-12 group-hover:text-white/10 transition-all duration-1000" size={320} />
