  return {
    id: String(i.id),
    name: i.name,
    description: i.description,
    price: i.price,
    category: i.category,
    image: i.image_url || i.image,
    stallName: stall?.name || 'Unknown Stall',
    stallId: String(i.stall_id),
    rating: i.rating || 5,
    isPopular: i.is_popular,
    isSpicy: i.is_spicy,
    isVeg: i.is_veg
  };
};

