import React, { useState, useEffect, useRef } from 'react';
import { MessageCircle, Send, Bot, Sparkles, ChevronDown } from 'lucide-react';
import { ChatMessage, MenuItem, Stall } from '../types';
import { sendMessageToGemini } from '../services/geminiService';
import { AnimatePresence, motion } from 'framer-motion';

interface ChatBotProps {
  menuItems: MenuItem[];
  stalls: Stall[];
}

export const ChatBot: React.FC<ChatBotProps> = ({ menuItems, stalls }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Hi there! I\'m **DineBot**. I can suggest the best meals at BUPC or answer menu questions. What are you craving today?',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    const responseText = await sendMessageToGemini(input, messages.map(m => ({ role: m.role, text: m.text })), menuItems, stalls);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: responseText, timestamp: new Date() }]);
    setIsLoading(false);
  };

  const formatMessageText = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) return <strong key={index} className="text-bupc-blue font-black">{part.slice(2, -2)}</strong>;
      return <span key={index}>{part}</span>;
    });
  };

  return (
    <div className="fixed bottom-24 right-4 left-4 sm:left-auto sm:w-80 z-[100] pointer-events-none">
      <AnimatePresence>
        {!isOpen && (
          <div className="flex justify-end pointer-events-auto">
              <motion.button
                initial={{ scale: 0, rotate: -45 }}
                animate={{ scale: 1, rotate: 0 }}
                exit={{ scale: 0, rotate: 45 }}
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => setIsOpen(true)}
                className="w-12 h-12 bg-bupc-blue text-white rounded-2xl shadow-xl flex items-center justify-center relative group"
              >
                <MessageCircle size={24} />
                <span className="absolute -top-1 -right-1 w-3 h-3 bg-bupc-orange rounded-full border-2 border-[#050810]"></span>
              </motion.button>
          </div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 50, scale: 0.95 }}
            className="pointer-events-auto bg-[#161B22] rounded-[2rem] shadow-3xl flex flex-col overflow-hidden border border-white/10 h-[420px]"
          >
            {/* Chat Header */}
            <div className="bg-bupc-blue/90 backdrop-blur-md text-white p-4 flex items-center justify-between border-b border-white/5">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-white/10 rounded-xl flex items-center justify-center">
                    <Bot size={18} className="text-white" />
                </div>
                <div>
                  <h3 className="font-black text-[11px] uppercase tracking-widest flex items-center gap-1">
                    DineBot <Sparkles size={10} className="text-bupc-orange" />
                  </h3>
                  <p className="text-[9px] text-blue-200 font-bold uppercase">Online & Ready</p>
                </div>
              </div>
              <button 
                onClick={() => setIsOpen(false)} 
                className="p-1.5 bg-white/5 hover:bg-white/10 rounded-lg transition-colors"
              >
                <ChevronDown size={18} />
              </button>
            </div>

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-black/20 no-scrollbar">
              {messages.map((msg) => (
                <motion.div 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    key={msg.id} 
                    className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`max-w-[85%] rounded-[1.25rem] px-3.5 py-2.5 text-[13px] leading-relaxed shadow-md ${
                      msg.role === 'user' 
                      ? 'bg-bupc-blue text-white rounded-tr-none' 
                      : 'bg-white/5 text-slate-200 border border-white/5 rounded-tl-none'
                  }`}>
                    {formatMessageText(msg.text)}
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                    <div className="bg-white/5 border border-white/5 rounded-2xl px-3 py-2 flex gap-1 shadow-sm">
                        <motion.span animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1 }} className="w-1 h-1 bg-white/40 rounded-full"></motion.span>
                        <motion.span animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1, delay: 0.2 }} className="w-1 h-1 bg-white/40 rounded-full"></motion.span>
                        <motion.span animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1, delay: 0.4 }} className="w-1 h-1 bg-white/40 rounded-full"></motion.span>
                    </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-3 bg-white/5 border-t border-white/5 flex gap-2">
              <input 
                type="text" 
                value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyDown={e => e.key === 'Enter' && handleSend()} 
                placeholder="Ask me for a spicy reco..." 
                className="flex-1 bg-black/20 rounded-xl px-4 text-xs font-medium text-white focus:ring-1 focus:ring-bupc-blue outline-none transition-all placeholder:text-slate-600" 
              />
              <motion.button 
                whileTap={{ scale: 0.9 }}
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="w-10 h-10 bg-bupc-blue text-white rounded-xl flex items-center justify-center disabled:opacity-30 shadow-lg"
              >
                <Send size={16} />
              </motion.button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

