        const { data, error } = await supabase.auth.signInWithPassword({ email: form.email, password: form.password });
        if (error) throw error;
        onAuth({ ...MOCK_USER, email: data.user.email, id: data.user.id });
      } else {
        const { data, error } = await supabase.auth.signUp({ 
          email: form.email, 
          password: form.password,
          options: { data: { full_name: form.name } }
        });
        if (error) throw error;
        onAuth({ ...MOCK_USER, name: form.name, email: data.user?.email, id: data.user?.id });
      }
    } catch (e: any) {
      setError(e.message || "Auth error. Check your credentials.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen ${THEME.bg} flex flex-col p-6 justify-center items-center`}>
      <motion.div initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className={`${THEME.surface} rounded-[3rem] p-10 shadow-3xl w-full max-w-sm border-white/20`}>
        <div className="w-16 h-16 bg-gradient-to-br from-bupc-orange to-red-600 rounded-[1.5rem] mb-6 flex items-center justify-center text-white shadow-2xl">
          <UtensilsCrossed size={32} />
        </div>
        <h2 className="text-3xl font-black text-white mb-1 tracking-tighter">{isLogin ? 'Hello!' : 'Join Us'}</h2>
        <p className="text-slate-400 text-[13px] mb-8">BUPC Intelligent Dining Hub.</p>

        {error && <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="mb-5 p-3.5 bg-red-500/10 border border-red-500/20 text-red-500 text-[11px] font-black rounded-xl">{error}</motion.div>}

        <div className="space-y-4">
          {!isLogin && <Input label="Full Name" placeholder="Juan Dela Cruz" value={form.name} onChange={(e:any) => setForm({...form, name: e.target.value})} />}
          <Input label="Student Email" placeholder="juan@bupc.edu.ph" value={form.email} onChange={(e:any) => setForm({...form, email: e.target.value})} />
          <Input label="Password" type="password" placeholder="••••••••" value={form.password} onChange={(e:any) => setForm({...form, password: e.target.value})} />

          <Button className="w-full h-14 rounded-[1.5rem] mt-3 text-base" onClick={handleAuth} disabled={loading}>
            {loading ? <Loader className="animate-spin" /> : isLogin ? 'Sign In' : 'Sign Up'}
          </Button>

          <button onClick={() => setIsLogin(!isLogin)} className="w-full text-center py-4 text-[9px] font-black uppercase text-slate-500 tracking-widest hover:text-white transition-colors">
            {isLogin ? "Need an account? Create one" : "Already have an account? Sign In"}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

