  const [filters, setFilters] = useState({ maxPrice: 300, isSpicy: false, isPopular: false });
  const navigate = useNavigate();

  const filteredItems = menuItems.filter(item => {
    const matchesCat = selectedCategory === 'All' || item.category === selectedCategory;
    const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesPrice = item.price <= filters.maxPrice;
    const matchesSpicy = !filters.isSpicy || item.isSpicy;
    const matchesPopular = !filters.isPopular || item.isPopular;
    return matchesCat && matchesSearch && matchesPrice && matchesSpicy && matchesPopular;
  });

  return (
    <PageTransition>
      <Header title="Marketplace" rightAction={
        <motion.button whileTap={{ scale: 0.9 }} onClick={() => setIsFilterOpen(true)} className="p-2.5 bg-white/10 rounded-xl text-white relative border border-white/5">
          <Filter size={18} />
