        <div className="relative">
          <Input 
            placeholder="Search for cravings..." 
            className="pl-12 h-14 bg-white/10 border-white/10 text-white rounded-xl text-xs" 
            value={searchQuery}
            onChange={(e:any) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
        </div>

        <div className="flex gap-2 overflow-x-auto no-scrollbar -mx-4 px-4 pb-1">
          {CATEGORIES.map(cat => (
            <Badge key={cat} active={selectedCategory === cat} onClick={() => setSelectedCategory(cat)}>{cat}</Badge>
          ))}
        </div>

        <div className="grid grid-cols-2 gap-4 pb-10">
          {filteredItems.map(item => <ProductCard key={item.id} item={item} onAdd={addToCart} onClick={() => navigate(`/food/${item.id}`)} />)}
