      </div>

      <Modal isOpen={isFilterOpen} onClose={() => setIsFilterOpen(false)} title="Market Filters">
        <div className="space-y-6">
          <div>
            <div className="flex justify-between items-center mb-3">
              <label className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Budget: ₱{filters.maxPrice}</label>
            </div>
            <input type="range" min="20" max="300" step="10" value={filters.maxPrice} onChange={e => setFilters({...filters, maxPrice: Number(e.target.value)})} className="w-full h-1.5 bg-white/10 rounded-full appearance-none accent-bupc-orange cursor-pointer" />
          </div>
          <div className="space-y-2.5">
             <label className="text-[9px] font-black uppercase text-slate-400 tracking-widest block mb-1">Tags</label>
             <div className="flex flex-wrap gap-2">
                <Badge active={filters.isSpicy} onClick={() => setFilters({...filters, isSpicy: !filters.isSpicy})}>🔥 Spicy</Badge>
