const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    Promise.all([supabase.from('stalls').select('*'), supabase.from('menu_items').select('*')])
      .then(([s, m]) => {
        const dbStalls = s.data?.length ? s.data.map(mapStall) : STALLS;
        const dbItems = m.data?.length ? m.data.map((i: any) => mapMenuItem(i, dbStalls)) : MENU_ITEMS;
        setStalls(dbStalls);
        setMenuItems(dbItems);
        setLoading(false);
      });
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = {
      id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`,
      items: [...items], subtotal, fee: 15, total,
      status: OrderStatus.PENDING, date: new Date(), paymentMethod: method
    };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex flex-col items-center justify-center`}>
      <motion.div animate={{ rotate: 360, scale: [1, 1.2, 1] }} transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }} className="w-16 h-16 bg-gradient-to-br from-bupc-orange to-red-600 rounded-2xl flex items-center justify-center text-white shadow-3xl">
