    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white selection:bg-bupc-orange/30 overflow-x-hidden relative`}>
      <div className="fixed top-[-20%] left-[-10%] w-[60%] h-[60%] bg-bupc-blue/10 blur-[150px] rounded-full pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-bupc-orange/10 blur-[150px] rounded-full pointer-events-none" />

