                <Badge active={filters.isPopular} onClick={() => setFilters({...filters, isPopular: !filters.isPopular})}>⭐ Student Choice</Badge>
             </div>
          </div>
          <Button className="w-full h-14 rounded-xl text-base font-black" onClick={() => setIsFilterOpen(false)}>Apply</Button>
        </div>
      </Modal>
    </PageTransition>
  );
};

