const ReviewSection: React.FC<{ 
  targetId: string; 
  targetType: 'stall' | 'menu_item'; 
  reviews: Review[];
  onAddReview: (rating: number, comment: string) => void;
}> = ({ targetId, targetType, reviews, onAddReview }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState('');
  const filtered = reviews.filter(r => r.targetId === targetId && r.targetType === targetType);

  const handleSubmit = () => {
    if (!comment.trim()) return;
    onAddReview(rating, comment);
    setComment('');
    setRating(5);
    setIsAdding(false);
  };

  return (
    <div className="mt-10 space-y-6">
      <div className="flex items-center justify-between px-2">
        <h3 className="text-[10px] font-black uppercase text-slate-500 tracking-[0.3em]">Student Reviews</h3>
