          onClick={() => setIsAdding(true)}
          className="text-[9px] font-black text-[#FF671F] uppercase tracking-widest bg-[#FF671F]/10 px-3 py-1.5 rounded-xl border border-[#FF671F]/20"
        >
          Write Review
        </button>
      </div>

      {filtered.length === 0 ? (
        <p className="text-[10px] text-slate-600 font-bold text-center py-6 border border-dashed border-white/5 rounded-[2rem]">No reviews yet. Be the first!</p>
      ) : (
        <div className="space-y-4">
          {filtered.map(r => (
            <div key={r.id} className={`${THEME.surface} p-5 rounded-[2rem] border-white/5 shadow-sm`}>
              <div className="flex justify-between items-start mb-2">
                <div className="flex items-center gap-3">
                  <img src={`https://ui-avatars.com/api/?name=${r.userName}&background=random`} className="w-8 h-8 rounded-xl shadow-md" alt="" />
                  <div>
                    <p className="text-[11px] font-black text-white">{r.userName}</p>
                    <p className="text-[9px] text-slate-500 font-bold">{new Date(r.date).toLocaleDateString()}</p>
                  </div>
                </div>
                <StarRating rating={r.rating} size={10} />
