// --- App Content & Root ---
const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [reviews, setReviews] = useState<Review[]>(MOCK_REVIEWS);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    Promise.all([supabase.from('stalls').select('*'), supabase.from('menu_items').select('*')])
      .then(([s, m]) => {
        const dbStalls = s.data?.length ? s.data.map(mapStall) : STALLS;
        const dbItems = m.data?.length ? m.data.map((i: any) => mapMenuItem(i, dbStalls)) : MENU_ITEMS;
        setStalls(dbStalls);
        setMenuItems(dbItems);
        setLoading(false);
      });
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const addReview = (targetId: string, targetType: 'stall' | 'menu_item', rating: number, comment: string) => {
    const newReview: Review = {
      id: `rev-${Date.now()}`,
      userId: user?.id || 'u-guest',
      userName: user?.name || 'Guest User',
      targetId,
      targetType,
      rating,
      comment,
      date: new Date()
    };
    setReviews(prev => [newReview, ...prev]);

    // Update the average rating for the menu item/stall locally
    if (targetType === 'menu_item') {
      setMenuItems(prev => prev.map(item => {
        if (item.id === targetId) {
          const itemReviews = [newReview, ...reviews.filter(r => r.targetId === targetId && r.targetType === 'menu_item')];
          const newAvg = itemReviews.reduce((sum, r) => sum + r.rating, 0) / itemReviews.length;
          return { ...item, rating: Number(newAvg.toFixed(1)), isPopular: newAvg >= 4.5 };
        }
        return item;
      }));
    }
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = {
      id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`,
      items: [...items], subtotal, fee: 15, total,
      status: OrderStatus.PENDING, date: new Date(), paymentMethod: method
    };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex flex-col items-center justify-center`}>
      <motion.div animate={{ rotate: 360, scale: [1, 1.2, 1] }} transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }} className="w-16 h-16 bg-gradient-to-br from-[#FF671F] to-red-600 rounded-2xl flex items-center justify-center text-white shadow-3xl">
        <UtensilsCrossed size={32} />
      </motion.div>
      <p className="mt-6 text-[9px] font-black uppercase text-slate-500 tracking-[0.4em] animate-pulse">Launching DineTime</p>
    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white selection:bg-[#FF671F]/30 overflow-x-hidden relative`}>
      <div className="fixed top-[-20%] left-[-10%] w-[60%] h-[60%] bg-[#0033A0]/10 blur-[150px] rounded-full pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-[#FF671F]/10 blur-[150px] rounded-full pointer-events-none" />

      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          {!onboardingComplete ? <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} /> : 
           !user ? <Route path="*" element={<AuthPage onAuth={setUser} />} /> : 
           <>
              <Route path="/" element={
                <PageTransition>
                  <Header showLocation />
                  <div className="space-y-10">
                    <motion.div 
                      whileHover={{ scale: 1.02 }}
                      className={`${THEME.surface} p-10 rounded-[3rem] shadow-3xl relative overflow-hidden group border-white/20`}
                    >
                      <div className="relative z-10">
                        <p className="text-[9px] font-black uppercase text-[#FF671F] tracking-[0.2em] mb-3">Daily Discovery</p>
                        <h1 className="text-3xl font-black mb-1 tracking-tighter leading-none">Stay Oragon,</h1>
                        <h1 className="text-3xl font-black mb-6 tracking-tighter text-blue-400">{user.name.split(' ')[0]}!</h1>
                        <Button size="md" className="rounded-xl h-11 font-black px-8" onClick={() => navigate('/menu')}>Explore Menu</Button>
                      </div>
                      <Sparkles className="absolute -right-8 -bottom-8 text-white/5 rotate-12 group-hover:text-white/10 transition-all duration-1000" size={240} />
                    </motion.div>

                    <div>
                      <div className="flex justify-between items-center mb-6 px-4">
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em]">Featured Stalls</h3>
                        <div className="w-8 h-1 h-white/10 rounded-full" />
                      </div>
                      <div className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
                        {stalls.map(s => <StallCard key={s.id} stall={s} onClick={() => navigate(`/stalls/${s.id}`)} />)}
                      </div>
                    </div>

                    <div>
                      <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Student Staples</h3>
                      <div className="grid grid-cols-2 gap-4 pb-20">
                        {menuItems.filter(i => i.isPopular).slice(0, 4).map(i => <ProductCard key={i.id} item={i} onAdd={addToCart} onClick={() => navigate(`/food/${i.id}`)} />)}
                      </div>
                    </div>
                  </div>
                </PageTransition>
              } />
              <Route path="/menu" element={<MenuPage addToCart={addToCart} menuItems={menuItems} />} />
              <Route path="/cart" element={
                <PageTransition>
                  <Header title="My Bag" />
                  <CartView cart={cart} setCart={setCart} placeOrder={placeOrder} addToCart={addToCart} />
                </PageTransition>
              } />
              <Route path="/orders" element={
                <PageTransition>
                  <Header title="Orders" />
                  <div className="space-y-4">
                    {orders.map(o => (
                      <motion.div 
                        whileTap={{ scale: 0.98 }}
                        onClick={() => navigate(`/orders/${o.id}`)}
                        key={o.id} className={`${THEME.surface} p-6 rounded-[2.5rem] flex items-center justify-between cursor-pointer border-white/10 shadow-2xl hover:bg-white/5 transition-colors`}
                      >
                        <div className="flex items-center gap-5">
                          <div className="w-12 h-12 bg-[#0033A0]/10 rounded-xl flex items-center justify-center text-[#0033A0] border border-[#0033A0]/10">
                            <ClipboardList size={22} />
                          </div>
                          <div>
                            <h4 className="font-black text-white text-base tracking-tight leading-none mb-1">#{o.id.slice(-6)}</h4>
                            <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">{o.status} • {o.items.length} Items</p>
                          </div>
                        </div>
                        <ChevronRight className="text-slate-700" size={18} />
                      </motion.div>
                    ))}
                    {orders.length === 0 && (
                      <div className="text-center py-16 opacity-20">
                        <ClipboardList size={60} className="mx-auto mb-4" />
                        <p className="text-[9px] font-black uppercase tracking-widest">Clean History</p>
                      </div>
                    )}
                  </div>
                </PageTransition>
              } />
              <Route path="/orders/:id" element={<OrderDetailsPage orders={orders} />} />
              <Route path="/stalls/:id" element={<StallDetailsPage stalls={stalls} menuItems={menuItems} addToCart={addToCart} reviews={reviews} onAddReview={(rating, comment) => {
                const { id } = location.pathname.split('/').pop() as any; 
                addReview(id, 'stall', rating, comment);
              }} />} />
              <Route path="/food/:id" element={<FoodDetailsPage addToCart={addToCart} menuItems={menuItems} reviews={reviews} onAddReview={addReview} />} />
              <Route path="/notifications" element={
                  <PageTransition>
                    <Header title="Inbox" backUrl="/" />
                    <div className="space-y-4">
                        {MOCK_NOTIFICATIONS.map(n => (
                            <motion.div whileTap={{ scale: 0.98 }} key={n.id} className={`${THEME.surface} p-6 rounded-[2rem] relative border-white/10 shadow-2xl`}>
                                <div className="flex justify-between items-start mb-2.5">
                                    <h4 className="font-black text-white text-sm leading-tight pr-4">{n.title}</h4>
                                    <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest whitespace-nowrap">{n.date.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                </div>
                                <p className="text-xs text-slate-400 leading-relaxed font-medium">{n.message}</p>
                                {!n.isRead && <span className="absolute top-6 left-3 w-1.5 h-1.5 bg-[#FF671F] rounded-full shadow-[0_0_10px_rgba(255,103,31,1)]"></span>}
                            </motion.div>
