              } />
              <Route path="/profile" element={
                <PageTransition>
                  <Header title="Account" />
                  <ProfileView user={user} setUser={setUser} />
                </PageTransition>
              } />
           </>}
        </Routes>
      </AnimatePresence>
      {user && <BottomNav cartCount={cart.length} />}
      {user && <ChatBot menuItems={menuItems} stalls={stalls} />}
    </div>
  );
};

