            <div className="col-span-2 text-center py-16">
              <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-700"><Search size={32} /></div>
              <p className="text-[10px] font-black uppercase text-slate-600 tracking-[0.3em]">No matching snacks</p>
