// --- Auth Page ---
const AuthPage: React.FC<{ onAuth: (user: any) => void }> = ({ onAuth }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ email: '', password: '', name: '' });
  const [error, setError] = useState('');

  const handleAuth = async () => {
    setLoading(true);
    setError('');
    try {
      if (isLogin) {
        const { data, error: signInError } = await supabase.auth.signInWithPassword({
          email: form.email,
          password: form.password,
        });
        if (signInError) throw signInError;
        onAuth({ ...MOCK_USER, email: data.user.email, id: data.user.id });
      } else {
        const { data, error: signUpError } = await supabase.auth.signUp({
          email: form.email,
          password: form.password,
          options: { data: { full_name: form.name } }
        });
        if (signUpError) throw signUpError;
        onAuth({ ...MOCK_USER, name: form.name, email: data.user?.email, id: data.user?.id });
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen ${THEME.bg} flex flex-col items-center justify-center p-8 relative overflow-hidden`}>
      <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-[#0033A0]/20 blur-[100px] rounded-full" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-[#FF671F]/20 blur-[100px] rounded-full" />

      <motion.div 
        initial={{ y: 30, opacity: 0 }} 
        animate={{ y: 0, opacity: 1 }} 
        className={`${THEME.surface} p-10 rounded-[3rem] w-full max-w-sm shadow-3xl relative z-10`}
      >
        <div className="w-16 h-16 bg-[#0033A0] rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl">
          <UtensilsCrossed size={32} />
        </div>
        <div className="text-center mb-8">
          <h2 className="text-2xl font-black text-white tracking-tighter mb-1">{isLogin ? 'Welcome Back' : 'Create Account'}</h2>
          <p className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em]">BUPC Intelligent Dining</p>
        </div>

        {error && <div className="mb-6 p-3 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black rounded-xl text-center">{error}</div>}

        <div className="space-y-4">
          {!isLogin && <Input label="Full Name" placeholder="Juan Dela Cruz" value={form.name} onChange={(e:any) => setForm({...form, name: e.target.value})} />}
          <Input label="Email Address" placeholder="user@bupc.edu.ph" value={form.email} onChange={(e:any) => setForm({...form, email: e.target.value})} />
          <Input label="Password" type="password" placeholder="••••••••" value={form.password} onChange={(e:any) => setForm({...form, password: e.target.value})} />

          <Button className="w-full h-14 rounded-2xl mt-4" onClick={handleAuth} disabled={loading}>
            {loading ? <Loader className="animate-spin" size={20} /> : (isLogin ? 'Sign In' : 'Sign Up')}
          </Button>

          <button 
            onClick={() => setIsLogin(!isLogin)}
            className="w-full py-4 text-[9px] font-black uppercase text-slate-500 tracking-widest hover:text-white transition-colors"
          >
            {isLogin ? "New to DineTime? Create Account" : "Already have an account? Sign In"}
          </button>
        </div>
      </motion.div>
