  );
};

// --- App Root Logic ---
const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [reviews, setReviews] = useState<Review[]>(MOCK_REVIEWS);
  const [stalls, setStalls] = useState<Stall[]>(STALLS);
  const [menuItems, setMenuItems] = useState<MenuItem[]>(MENU_ITEMS);
  const [loading, setLoading] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    // Initial data fetch
    setLoading(false);
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const handleAddReview = (targetId: string, targetType: 'stall' | 'menu_item', rating: number, comment: string) => {
    const newReview: Review = {
      id: `rev-${Date.now()}`,
      userId: user?.id || 'guest',
      userName: user?.name || 'Guest User',
      targetId,
      targetType,
      rating,
      comment,
      date: new Date()
    };
    setReviews(prev => [newReview, ...prev]);

    // If it's a 5-star review, potentially update 'Popular' status
    if (targetType === 'menu_item') {
      const fiveStarCount = [newReview, ...reviews].filter(r => r.targetId === targetId && r.rating === 5).length;
      if (fiveStarCount >= 3) {
        setMenuItems(prev => prev.map(i => i.id === targetId ? { ...i, isPopular: true } : i));
      }
    }
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = {
      id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`,
      items: [...items], subtotal, fee: 15, total,
      status: OrderStatus.PENDING, date: new Date(), paymentMethod: method
    };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex items-center justify-center`}>
      <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }} className="text-[#FF671F]">
        <Loader size={48} />
      </motion.div>
    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white selection:bg-[#FF671F]/30 overflow-x-hidden relative`}>
      {/* Global Background Decorations - Fixed unclickable by pointer-events-none */}
      <div className="fixed top-[-20%] left-[-10%] w-[60%] h-[60%] bg-[#0033A0]/10 blur-[150px] rounded-full pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-[#FF671F]/10 blur-[150px] rounded-full pointer-events-none" />

      {!user ? <AuthPage onAuth={setUser} /> : (
        <>
          <AnimatePresence mode="wait">
            <Routes location={location} key={location.pathname}>
              <Route path="/" element={
                <PageTransition>
                  <Header showLocation />
                  <div className="space-y-10">
                    <motion.div 
                      whileHover={{ scale: 1.02 }}
                      className={`${THEME.surface} p-10 rounded-[3rem] shadow-3xl relative overflow-hidden group border-white/20`}
                    >
                      <div className="relative z-10">
                        <p className="text-[9px] font-black uppercase text-[#FF671F] tracking-[0.2em] mb-3">Today's Suggestion</p>
                        <h1 className="text-3xl font-black mb-1 tracking-tighter leading-none">Stay Oragon,</h1>
                        <h1 className="text-3xl font-black mb-6 tracking-tighter text-blue-400">{user.name.split(' ')[0]}!</h1>
                        <Button size="md" className="rounded-xl h-11 px-8" onClick={() => navigate('/menu')}>Explore Menu</Button>
                      </div>
                      <Sparkles className="absolute -right-8 -bottom-8 text-white/5 rotate-12 group-hover:text-white/10 transition-all duration-1000" size={240} />
                    </motion.div>

                    <div>
                      <div className="flex justify-between items-center mb-6 px-4">
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em]">Featured Stalls</h3>
                        <div className="w-8 h-1 bg-white/10 rounded-full" />
                      </div>
                      <div className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
                        {stalls.map(s => (
                          <motion.div 
                            key={s.id} 
                            whileTap={{ scale: 0.95 }}
                            onClick={() => navigate(`/stalls/${s.id}`)}
                            className="min-w-[200px] h-36 relative rounded-[2.5rem] overflow-hidden border border-white/10 group cursor-pointer"
                          >
                            <img src={s.image} className="w-full h-full object-cover group-hover:scale-110 transition-all duration-700" />
                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent p-5 flex flex-col justify-end">
                              <h4 className="text-[12px] font-black text-white">{s.name}</h4>
