      <div className="fixed top-[-20%] left-[-10%] w-[60%] h-[60%] bg-[#0033A0]/10 blur-[150px] rounded-full pointer-events-none" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-[#FF671F]/10 blur-[150px] rounded-full pointer-events-none" />

      <AnimatePresence mode="wait">
        {!onboardingComplete ? (
          <Routes location={location} key="onboarding">
            <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} />
          </Routes>
        ) : !user ? (
          <Routes location={location} key="auth">
            <Route path="*" element={<AuthPage onAuth={setUser} />} />
          </Routes>
        ) : (
          <>
            <Routes location={location} key={location.pathname}>
              <Route path="/" element={
                <PageTransition>
                  <Header showLocation />
                  <div className="space-y-10">
                    <motion.div 
                      whileHover={{ scale: 1.02 }}
                      className={`${THEME.surface} p-10 rounded-[3rem] shadow-3xl relative overflow-hidden group border-white/20`}
                    >
                      <div className="relative z-10">
                        <p className="text-[9px] font-black uppercase text-[#FF671F] tracking-[0.2em] mb-3">Today's Suggestion</p>
                        <h1 className="text-3xl font-black mb-1 tracking-tighter leading-none">Stay Oragon,</h1>
                        <h1 className="text-3xl font-black mb-6 tracking-tighter text-blue-400">{user.name.split(' ')[0]}!</h1>
                        <Button size="md" className="rounded-xl h-11 px-8" onClick={() => navigate('/menu')}>Explore Menu</Button>
                      </div>
                      <Sparkles className="absolute -right-8 -bottom-8 text-white/5 rotate-12 group-hover:text-white/10 transition-all duration-1000" size={240} />
                    </motion.div>

                    <div>
                      <div className="flex justify-between items-center mb-6 px-4">
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em]">Featured Stalls</h3>
                        <div className="w-8 h-1 bg-white/10 rounded-full" />
                      </div>
                      <div className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
                        {stalls.map(s => (
                          <motion.div 
                            key={s.id} 
                            whileTap={{ scale: 0.95 }}
                            onClick={() => navigate(`/stalls/${s.id}`)}
                            className="min-w-[200px] h-36 relative rounded-[2.5rem] overflow-hidden border border-white/10 group cursor-pointer"
                          >
                            <img src={s.image} className="w-full h-full object-cover group-hover:scale-110 transition-all duration-700" />
                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent p-5 flex flex-col justify-end">
                              <h4 className="text-[12px] font-black text-white">{s.name}</h4>
                              <p className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{s.openTime} - {s.closeTime}</p>
                            </div>
                          </motion.div>
                        ))}
                      </div>
                    </div>

                    <div>
                      <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Most Loved (5★)</h3>
                      <div className="grid grid-cols-2 gap-4 pb-20">
                        {menuItems.filter(i => i.isPopular).slice(0, 4).map(i => (
                          <ProductCard key={i.id} item={i} onAdd={addToCart} onClick={() => navigate(`/food/${i.id}`)} />
                        ))}
                      </div>
                    </div>
                  </div>
                </PageTransition>
              } />

              <Route path="/menu" element={
                <PageTransition>
                  <MarketplaceView menuItems={menuItems} addToCart={addToCart} />
                </PageTransition>
              } />

              <Route path="/food/:id" element={
                <FoodDetailsView 
                  menuItems={menuItems} 
                  reviews={reviews} 
                  favorites={favorites}
                  toggleFavorite={toggleFavorite}
                  addToCart={addToCart} 
                  onAddReview={handleAddReview} 
                />
              } />

              <Route path="/stalls/:id" element={
                <PageTransition>
                  <StallDetailsView stalls={stalls} menuItems={menuItems} addToCart={addToCart} reviews={reviews} onAddReview={handleAddReview} />
                </PageTransition>
              } />

              <Route path="/cart" element={
                <PageTransition>
                  <Header title="Your Cart" />
                  <CartView cart={cart} setCart={setCart} placeOrder={placeOrder} addToCart={addToCart} />
                </PageTransition>
              } />

              <Route path="/orders" element={
                <PageTransition>
                  <Header title="Orders History" />
                  <div className="space-y-4">
                    {orders.map(o => (
                      <motion.div 
                        whileTap={{ scale: 0.98 }}
                        onClick={() => navigate(`/orders/${o.id}`)}
                        key={o.id} className={`${THEME.surface} p-5 rounded-[2rem] flex items-center justify-between cursor-pointer border-white/10 shadow-2xl hover:bg-white/5 transition-colors`}
                      >
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 bg-[#0033A0]/10 rounded-xl flex items-center justify-center text-[#0033A0] border border-[#0033A0]/10">
                            <ClipboardList size={20} />
                          </div>
                          <div>
                            <h4 className="font-black text-white text-sm tracking-tight leading-none mb-1">Order #{o.id.slice(-6)}</h4>
                            <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">{o.status} • {o.items.length} Items</p>
                          </div>
                        </div>
                        <ChevronRight className="text-slate-700" size={16} />
                      </motion.div>
                    ))}
                    {orders.length === 0 && (
                      <div className="text-center py-20 opacity-10">
                        <ClipboardList size={80} className="mx-auto" />
                        <p className="font-black uppercase tracking-widest text-xs mt-4">Empty History</p>
                      </div>
                    )}
                  </div>
                </PageTransition>
              } />

              <Route path="/profile" element={
                <PageTransition>
                  <Header title="Profile" />
                  <ProfileView user={user} setUser={setUser} />
                </PageTransition>
              } />

              <Route path="/notifications" element={
                <PageTransition>
                  <Header title="Alerts" backUrl="/" />
                  <div className="space-y-4">
                    {MOCK_NOTIFICATIONS.map(n => (
                      <div key={n.id} className={`${THEME.surface} p-5 rounded-[2rem] relative border-white/10`}>
                        <h4 className="font-black text-white text-xs mb-1">{n.title}</h4>
                        <p className="text-[11px] text-slate-400 leading-relaxed">{n.message}</p>
                        {!n.isRead && <span className="absolute top-5 right-5 w-2 h-2 bg-[#FF671F] rounded-full" />}
                      </div>
                    ))}
                  </div>
                </PageTransition>
              } />
            </Routes>
            <BottomNav cartCount={cart.length} />
            <ChatBot menuItems={menuItems} stalls={stalls} />
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

