              } />

              <Route path="/menu" element={
                <PageTransition>
                  <MarketplaceView menuItems={menuItems} addToCart={addToCart} />
                </PageTransition>
              } />

              <Route path="/food/:id" element={
                <FoodDetailsView 
                  menuItems={menuItems} 
                  reviews={reviews} 
                  favorites={favorites}
                  toggleFavorite={toggleFavorite}
                  addToCart={addToCart} 
                  onAddReview={handleAddReview} 
                />
              } />

              <Route path="/stalls/:id" element={
                <PageTransition>
                  <StallDetailsView stalls={stalls} menuItems={menuItems} addToCart={addToCart} reviews={reviews} onAddReview={handleAddReview} />
                </PageTransition>
              } />

              <Route path="/cart" element={
                <PageTransition>
                  <Header title="Your Cart" />
                  <CartView cart={cart} setCart={setCart} placeOrder={placeOrder} addToCart={addToCart} />
                </PageTransition>
              } />

              <Route path="/orders" element={
                <PageTransition>
                  <Header title="My Orders" />
                  <OrdersListView orders={orders} />
                </PageTransition>
              } />

              <Route path="/orders/:id" element={
                <PageTransition>
                  <OrderDetailView orders={orders} />
                </PageTransition>
              } />

              <Route path="/profile" element={
                <PageTransition>
                  <Header title="Profile" />
                  <ProfileView user={user} setUser={setUser} />
                </PageTransition>
              } />

              <Route path="/notifications" element={
                <PageTransition>
                  <Header title="Alerts" backUrl="/" />
                  <div className="space-y-4">
                    {MOCK_NOTIFICATIONS.map(n => (
                      <div key={n.id} className={`${THEME.surface} p-5 rounded-[2rem] relative border-white/10`}>
                        <h4 className="font-black text-white text-xs mb-1">{n.title}</h4>
                        <p className="text-[11px] text-slate-400 leading-relaxed">{n.message}</p>
                        {!n.isRead && <span className="absolute top-5 right-5 w-2 h-2 bg-[#FF671F] rounded-full" />}
                      </div>
                    ))}
                  </div>
                </PageTransition>
              } />
            </Routes>
            <BottomNav cartCount={cart.length} />
            <ChatBot menuItems={menuItems} stalls={stalls} />
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

