Context Data:
Menu Items: ${JSON.stringify(menuItems.map(i => `${i.name} (${i.category}) - ₱${i.price} at ${i.stallName}. Attributes: ${i.isSpicy ? 'Spicy' : ''} ${i.isVeg ? 'Vegetarian' : ''}`))}
