export const sendMessageToGemini = async (
  message: string,
  history: { role: 'user' | 'model'; text: string }[],
  menuItems: MenuItem[],
  stalls: Stall[]
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Construct contents correctly: history followed by the new user message
    const contents = [
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: message }] }
    ];

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: generateSystemInstruction(menuItems, stalls),
        temperature: 0.7,
        topP: 0.95,
      },
    });

    return response.text || "I couldn't generate a response. Please try again.";
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("API_KEY")) {
      return "The AI service is currently unavailable due to an invalid API Key.";
    }
    return "DineBot is resting right now. Please try again in a few moments!";
  }
};

