const AuthPage: React.FC<{ onAuth: (user: any) => void }> = ({ onAuth }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ email: '', password: '', name: '' });
  const [error, setError] = useState('');

  const handleAuth = async () => {
    setLoading(true);
    setError('');
    try {
      if (isLogin) {
        const { data, error: signInError } = await supabase.auth.signInWithPassword({ email: form.email, password: form.password });
        if (signInError) throw signInError;
        if (data?.user) {
          const { data: profile } = await supabase.from('profiles').select('*').eq('id', data.user.id).maybeSingle();
          onAuth(profile || { ...MOCK_USER, email: data.user.email, id: data.user.id, name: data.user.user_metadata?.full_name || 'BUPC User' });
        }
      } else {
        const { data, error: signUpError } = await supabase.auth.signUp({ email: form.email, password: form.password, options: { data: { full_name: form.name } } });
        if (signUpError) throw signUpError;
        if (data?.user) {
          const newProfile = { id: data.user.id, name: form.name, email: form.email, userType: 'Student' };
          await supabase.from('profiles').insert([newProfile]);
          onAuth({ ...MOCK_USER, ...newProfile });
        }
      }
    } catch (err: any) { setError(err.message || 'Authentication failed.'); } finally { setLoading(false); }
  };

  return (
    <div className={`min-h-screen ${THEME.bg} flex flex-col items-center justify-center p-8 relative overflow-hidden`}>
      <motion.div initial={{ y: 30, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className={`${THEME.surface} p-10 rounded-[3.5rem] w-full max-w-sm shadow-3xl relative z-10 border-white/20`}>
