        {error && <div className="mb-6 p-3.5 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black rounded-2xl text-center">{error}</div>}
        <div className="space-y-4">
          {!isLogin && <Input label="Full Name" placeholder="Juan Dela Cruz" value={form.name} onChange={(e:any) => setForm({...form, name: e.target.value})} />}
          <Input label="Email" placeholder="user@bupc.edu.ph" value={form.email} onChange={(e:any) => setForm({...form, email: e.target.value})} />
          <Input label="Password" type="password" placeholder="••••••••" value={form.password} onChange={(e:any) => setForm({...form, password: e.target.value})} />
          <Button className="w-full h-16 rounded-[2rem] mt-4 text-base shadow-2xl" onClick={handleAuth} disabled={loading}>{loading ? <Loader className="animate-spin" size={20} /> : (isLogin ? 'Sign In' : 'Sign Up')}</Button>
          <button onClick={() => setIsLogin(!isLogin)} className="w-full py-4 text-[10px] font-black uppercase text-slate-500 tracking-widest hover:text-white transition-colors">{isLogin ? "New to DineTime? Create Account" : "Already have an account? Sign In"}</button>
          <div className="pt-4 border-t border-white/5"><button onClick={() => onAuth(MOCK_USER)} className="w-full py-3 bg-white/5 rounded-2xl text-[10px] font-black uppercase text-blue-400 tracking-widest border border-blue-500/20">Try Demo Mode</button></div>
