  const [reviews, setReviews] = useState<Review[]>(MOCK_REVIEWS);
  const [stalls, setStalls] = useState<Stall[]>(STALLS);
  const [menuItems, setMenuItems] = useState<MenuItem[]>(MENU_ITEMS);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  const toggleFavorite = async (itemId: string) => {
    const isFav = favorites.includes(itemId);
    const newFavs = isFav ? favorites.filter(id => id !== itemId) : [...favorites, itemId];
    setFavorites(newFavs);
    if (user) { await supabase.from('profiles').update({ favorites: newFavs }).eq('id', user.id); }
  };

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = { id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`, items: [...items], subtotal, fee: 15, total, status: OrderStatus.PENDING, date: new Date(), paymentMethod: method };
    setOrders(prev => [newOrder, ...prev]);
  };

  return (
    <div className={`min-h-screen ${THEME.bg} text-white relative`}>
      <AnimatePresence mode="wait">
        {!onboardingComplete ? (
          <Routes location={location} key="onboarding"><Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} /></Routes>
        ) : !user ? (
          <Routes location={location} key="auth"><Route path="*" element={<AuthPage onAuth={setUser} />} /></Routes>
        ) : (
          <>
            <Routes location={location} key={location.pathname}>
              <Route path="/" element={<PageTransition><Header showLocation /><div className="space-y-10"><motion.div className={`${THEME.surface} p-10 rounded-[3rem] shadow-3xl relative overflow-hidden group border-white/20`}><div className="relative z-10"><p className="text-[9px] font-black uppercase text-[#FF671F] tracking-[0.2em] mb-3">Welcome to BUPC</p><h1 className="text-3xl font-black mb-1">Stay Oragon,</h1><h1 className="text-3xl font-black mb-6 text-blue-400">{user.name.split(' ')[0]}!</h1><Button size="md" className="rounded-xl h-11 px-8" onClick={() => navigate('/menu')}>Order Food</Button></div><Sparkles className="absolute -right-8 -bottom-8 text-white/5 rotate-12" size={240} /></motion.div><div><div className="flex justify-between items-center mb-6 px-4"><h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em]">Featured Stalls</h3></div><div className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">{stalls.map(s => (<motion.div key={s.id} whileTap={{ scale: 0.95 }} onClick={() => navigate(`/stalls/${s.id}`)} className="min-w-[200px] h-36 relative rounded-[2.5rem] overflow-hidden border border-white/10 group cursor-pointer"><img src={s.image} className="w-full h-full object-cover" /><div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent p-5 flex flex-col justify-end"><h4 className="text-[12px] font-black text-white">{s.name}</h4><p className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{s.openTime} - {s.closeTime}</p></div></motion.div>))}</div></div><div><h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Most Popular</h3><div className="grid grid-cols-2 gap-4 pb-20">{menuItems.filter(i => i.isPopular).slice(0, 4).map(i => (<ProductCard key={i.id} item={i} onAdd={addToCart} onClick={() => navigate(`/food/${i.id}`)} />))}</div></div></div></PageTransition>} />
