import { GoogleGenAI } from "@google/genai";
import { MenuItem, Stall } from '../types';

const generateSystemInstruction = (menuItems: MenuItem[], stalls: Stall[]) => `
You are "DineBot", the intelligent food assistant for DineTime at Bicol University Polangui Campus (BUPC).
Your goal is to help students and staff find food, recommend meals, and answer questions about the campus menu.

Context:
Stalls: ${stalls.map(s => s.name).join(', ')}
Menu: ${menuItems.map(i => `${i.name} (₱${i.price} at ${i.stallName})`).join('; ')}

Strict Guidelines:
1. ALWAYS provide helpful, friendly, and complete sentences.
2. NEVER respond with single words or cryptic commands like "launch", "lunch", or "ok".
3. Use a Bicolano friendly tone (e.g., "Oragon!", "Maayong aga").
4. If a user asks for a recommendation, pick a specific item from the menu above.
5. Keep answers concise but conversational (2-3 sentences).
`;

export const sendMessageToGemini = async (
  message: string,
  history: { role: 'user' | 'model'; text: string }[],
  menuItems: MenuItem[],
  stalls: Stall[]
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Ensure history is a clean array of turns
    const contents = [
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: message }] }
    ];

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: generateSystemInstruction(menuItems, stalls),
        temperature: 0.8,
        topP: 0.95,
        maxOutputTokens: 250,
      },
    });

    const result = response.text?.trim();
    if (!result || result.length < 2) {
      return "I'm here to help! What kind of food are you looking for today at BUPC?";
    }
    return result;
  } catch (error: any) {
    console.error("DineBot Error:", error);
    return "I'm a bit overwhelmed with orders right now. Could you ask me again in a second?";
  }
};

