import { GoogleGenAI } from "@google/genai";
import { MenuItem, Stall } from '../types';

const generateSystemInstruction = (menuItems: MenuItem[], stalls: Stall[]) => `
You are "DineBot", the intelligent food concierge for DineTime at Bicol University Polangui Campus (BUPC).

CONTEXT DATA:
- STALLS: ${stalls.map(s => s.name).join(', ')}
- MENU: ${menuItems.map(i => `${i.name} (₱${i.price} at ${i.stallName})`).join('; ')}

STRICT OPERATING RULES:
1. ALWAYS respond with full, helpful sentences. 
2. NEVER output single words like "launch", "lunch", "ok", or "hello". 
3. If you don't know the answer, recommend a popular item like the "Special Bicol Express" or "Spicy Tuna Pasta".
4. Use a friendly "Oragon" BUPC tone.
5. Provide specific meal recommendations based on the user's request using only the menu items provided above.
6. Keep responses between 2 to 4 sentences.
`;

export const sendMessageToGemini = async (
  message: string,
  history: { role: 'user' | 'model'; text: string }[],
  menuItems: MenuItem[],
  stalls: Stall[]
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Construct the contents correctly for a multi-turn conversation
    const contents = [
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: message }] }
    ];

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: generateSystemInstruction(menuItems, stalls),
        temperature: 0.7,
        topP: 0.8,
        maxOutputTokens: 300,
      },
    });

    const reply = response.text?.trim() || "";

    // Emergency filter for one-word hallucinations
    if (reply.split(' ').length < 2 || reply.toLowerCase().includes('launch')) {
      return "I'm ready to help you find the best meals at BUPC! Are you looking for something spicy like Bicol Express, or perhaps a quick snack?";
    }

    return reply;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    return "Mataas ang traffic sa BUPC! (I'm a bit busy). Please try asking me again in a moment.";
  }
};

