const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [reviews, setReviews] = useState<Review[]>(MOCK_REVIEWS);
  const [menuItems, setMenuItems] = useState<MenuItem[]>(MENU_ITEMS);
  const [favorites, setFavorites] = useState<string[]>([]);
  const navigate = useNavigate();
  const location = useLocation();

  const handleAddReview = (targetId: string, targetType: 'stall' | 'menu_item', rating: number, comment: string) => {
    const newReview: Review = { id: `r${Date.now()}`, userId: user?.id || 'u1', userName: user?.name || 'User', targetId, targetType, rating, comment, date: new Date() };
    setReviews(prev => [newReview, ...prev]);
  };

  const toggleFavorite = async (id: string) => {
    const isFav = favorites.includes(id);
    const newFavs = isFav ? favorites.filter(f => f !== id) : [...favorites, id];
    setFavorites(newFavs);
    if (user) { await supabase.from('profiles').update({ favorites: newFavs }).eq('id', user.id); }
  };

  const addToCart = (item: MenuItem) => setCart(prev => {
    const existing = prev.find(i => i.id === item.id);
    if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
    return [...prev, { ...item, quantity: 1 }];
  });

  if (!user) return <AuthPage onAuth={setUser} />;

  return (
    <div className={`min-h-screen ${THEME.bg} text-white`}>
      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          <Route path="/" element={<PageTransition><Header showLocation /><div className="space-y-10">
            <motion.div className="bg-white/5 p-10 rounded-[3rem] border border-white/10 relative overflow-hidden">
              <div className="relative z-10"><h1 className="text-3xl font-black mb-1">Stay Oragon,</h1><h1 className="text-3xl font-black mb-6 text-blue-400">{user.name.split(' ')[0]}!</h1><Button size="md" className="rounded-xl h-11 px-8" onClick={() => navigate('/menu')}>Order Food</Button></div>
              <Sparkles className="absolute -right-8 -bottom-8 text-white/5 rotate-12" size={200} />
            </motion.div>
            <div>
                <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Campus Stalls</h3>
                <div className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
                    {STALLS.map(s => (
                        <motion.div key={s.id} whileTap={{ scale: 0.95 }} onClick={() => navigate(`/stalls/${s.id}`)} className="min-w-[200px] h-36 relative rounded-[2.5rem] overflow-hidden border border-white/10 cursor-pointer">
                            <img src={s.image} className="w-full h-full object-cover" />
                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent p-5 flex flex-col justify-end">
                                <h4 className="text-[12px] font-black text-white">{s.name}</h4>
                            </div>
                        </motion.div>
                    ))}
                </div>
            </div>
            <div><h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Daily Specials</h3><div className="grid grid-cols-2 gap-4 pb-20">{menuItems.slice(0, 4).map(i => (<ProductCard key={i.id} item={i} onAdd={addToCart} onClick={() => navigate(`/food/${i.id}`)} />))}</div></div>
          </div></PageTransition>} />

          <Route path="/menu" element={<PageTransition><MarketplaceView menuItems={menuItems} addToCart={addToCart} /></PageTransition>} />
          <Route path="/stalls/:id" element={<PageTransition><StallDetailsView stalls={STALLS} menuItems={menuItems} addToCart={addToCart} reviews={reviews} onAddReview={handleAddReview} /></PageTransition>} />
          <Route path="/food/:id" element={<FoodDetailsView menuItems={menuItems} reviews={reviews} favorites={favorites} toggleFavorite={toggleFavorite} addToCart={addToCart} onAddReview={handleAddReview} />} />
          <Route path="/orders" element={<PageTransition><Header title="Orders" /><OrdersListView orders={orders} /></PageTransition>} />
          <Route path="/orders/:id" element={<PageTransition><OrderDetailView orders={orders} /></PageTransition>} />
          <Route path="/profile" element={<PageTransition><Header title="Profile" /><ProfileView user={user} setUser={setUser} /></PageTransition>} />

          <Route path="/cart" element={<PageTransition><Header title="Cart" /><CartView cart={cart} setCart={setCart} onCheckout={(method: any) => {
            const subtotal = cart.reduce((s, i) => s + (i.price * i.quantity), 0);
            const newOrder: Order = { id: `ORD${Date.now()}`, items: [...cart], subtotal, fee: 15, total: subtotal + 15, status: OrderStatus.PENDING, date: new Date(), paymentMethod: method };
            setOrders(prev => [newOrder, ...prev]);
            setCart([]);
            navigate('/orders');
          }} addToCart={addToCart} /></PageTransition>} />
        </Routes>
      </AnimatePresence>
      <BottomNav cartCount={cart.length} /><ChatBot menuItems={menuItems} stalls={STALLS} />
    </div>
  );
};

