                <div className="bg-white/5 p-5 rounded-3xl flex items-center gap-5 border border-white/5"><Phone className="text-green-400" /><div><p className="text-[8px] font-black text-slate-500 uppercase">Contact</p><p className="text-xs font-black">{user.phone || '09XX XXX XXXX'}</p></div></div>
