                        <p className="text-[8px] font-black text-slate-500 uppercase">Account Category</p>
                        <div className="flex gap-2">
                            {['Student', 'Faculty', 'Staff'].map(t => (
                                <button key={t} onClick={() => setForm({...form, userType: t})} className={`flex-1 py-3 rounded-xl text-[9px] font-black border ${form.userType === t ? 'bg-[#FF671F] border-[#FF671F] text-white' : 'bg-white/5 border-white/10 text-slate-500'}`}>{t}</button>
                            ))}
                        </div>
                    </div>
                    <Input label="Course/Department" value={form.course || form.department} onChange={(e:any) => setForm({...form, course: e.target.value, department: e.target.value})} />
                    <Input label="Phone Number" value={form.phone} onChange={(e:any) => setForm({...form, phone: e.target.value})} />
                    <Button className="w-full h-14 rounded-2xl mt-4" onClick={save}>Apply Changes</Button>
                </div>
