 * uses the provided menu context accurately, and avoids cryptic one-word responses.
 */
const generateSystemInstruction = (menuItems: MenuItem[], stalls: Stall[]) => `
You are "DineBot", the world-class intelligent food concierge for the DineTime app at Bicol University Polangui Campus (BUPC).

CORE IDENTITY & TONE:
- Be helpful, conversational, and energetic.
- Use a friendly "Oragon" BUPC spirit. Occasionally use local terms like "Maayong aga" (Good morning) or "Salamat" (Thank you).
- Your personality is a mix of a savvy food critic and a helpful campus senior.

KNOWLEDGE BASE (ONLY use these items for recommendations):
- STALLS: ${stalls.map(s => s.name).join(', ')}
- MENU ITEMS: ${menuItems.map(i => `${i.name} (₱${i.price} at ${i.stallName}) - ${i.description}`).join('; ')}

RESPONSE GUIDELINES:
1. ALWAYS provide complete, multi-word sentences. 
2. NEVER respond with just "launch", "lunch", "ok", or any single-word commands. If you are confused, ask for clarification.
3. When recommending, explain WHY an item is good (e.g., "The Special Bicol Express at Polangui Eats is a must-try because of its rich coconut milk and authentic spicy kick!").
4. If asked about prices or location, provide accurate details based on the provided context.
5. Keep responses between 2 to 4 sentences long to fit nicely in a mobile chat bubble.
6. Emphasize the BUPC colors (Blue and Orange) or the student lifestyle when appropriate.
`;

export const sendMessageToGemini = async (
  message: string,
  history: { role: 'user' | 'model'; text: string }[],
  menuItems: MenuItem[],
  stalls: Stall[]
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Ensure the conversation starts with a 'user' turn if history exists
    const contents = [
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: message }] }
    ];

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Upgraded to the pro model as requested
      contents: contents,
      config: {
        systemInstruction: generateSystemInstruction(menuItems, stalls),
        temperature: 0.8, // Slightly higher for more creative/natural language
        topP: 0.95,
        maxOutputTokens: 500,
      },
    });

    const reply = response.text?.trim() || "";

    // Robust guard against hallucinations or empty replies
    if (reply.length < 5 || reply.toLowerCase() === 'launch' || reply.toLowerCase() === 'lunch') {
      return "I'm ready to help you discover the best flavors at BUPC! Are you looking for a heavy meal like Bicol Express, or maybe a quick snack from Campus Bytes?";
    }

    return reply;
  } catch (error) {
    console.error("DineBot Connection Error:", error);
    return "Mataas ang traffic sa canteen! (The AI is currently busy). Please try asking me again in a moment, Oragon!";
  }
};

/**
 * Provides a one-word recommendation based on user preferences.
 * Uses the faster Flash model for quick UI updates.
 */
export const getSmartRecommendation = async (userPreferences: string, menuItems: MenuItem[]): Promise<string> => {
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `User likes: ${userPreferences}. From this menu: ${JSON.stringify(menuItems.map(i => i.name))}, suggest exactly one item name.`,
            config: {
                systemInstruction: "You are a fast recommendation engine. Return ONLY the name of the meal item. No punctuation, no extra words.",
            },
        });
        return response.text?.trim() || "";
    } catch (e) {
        return "";
    }
}

import React, { useState, useEffect, useRef } from 'react';
