import { sendMessageToGemini } from '../services/geminiService';
import { AnimatePresence, motion } from 'framer-motion';

interface ChatBotProps {
  menuItems: MenuItem[];
  stalls: Stall[];
}

export const ChatBot: React.FC<ChatBotProps> = ({ menuItems, stalls }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Maayong adlaw! I\'m **DineBot**. Ask me for a Bicolano reco or budget-friendly meals at BUPC!',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isOpen, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text: input, 
      timestamp: new Date() 
    };

    // Prepare history: ensure it starts with 'user'
    const historyForAi = messages
      .filter(m => m.id !== 'welcome')
      .map(m => ({ role: m.role, text: m.text }));

    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(currentInput, historyForAi, menuItems, stalls);
      setMessages(prev => [...prev, { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: responseText, 
        timestamp: new Date() 
      }]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { 
        id: 'error', 
        role: 'model', 
        text: "I'm having a bit of trouble connecting to the campus servers. Mind trying again?", 
        timestamp: new Date() 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const formatMessageText = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) return <strong key={index} className="text-[#FF671F] font-black">{part.slice(2, -2)}</strong>;
      return <span key={index}>{part}</span>;
    });
  };

  return (
    <div className="fixed bottom-24 right-4 left-4 sm:left-auto sm:w-80 z-[100] pointer-events-none">
      <AnimatePresence>
        {!isOpen && (
          <div className="flex justify-end pointer-events-auto">
              <motion.button
                initial={{ scale: 0, rotate: -45 }}
                animate={{ scale: 1, rotate: 0 }}
                exit={{ scale: 0, rotate: 45 }}
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => setIsOpen(true)}
                className="w-14 h-14 bg-[#0033A0] text-white rounded-2xl shadow-[0_15px_30px_rgba(0,51,160,0.3)] flex items-center justify-center relative group border border-white/10"
              >
                <Bot size={28} />
                <span className="absolute -top-1 -right-1 w-4 h-4 bg-[#FF671F] rounded-full border-2 border-[#050810] shadow-sm animate-pulse"></span>
              </motion.button>
          </div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 50, scale: 0.95 }}
            className="pointer-events-auto bg-[#0a0d14] rounded-[2.5rem] shadow-3xl flex flex-col overflow-hidden border border-white/10 h-[420px]"
          >
            {/* Header */}
            <div className="bg-[#0033A0] text-white p-5 flex items-center justify-between border-b border-white/5 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-2 opacity-10"><Bot size={80} /></div>
              <div className="flex items-center gap-3 relative z-10">
                <div className="w-10 h-10 bg-white/10 rounded-2xl flex items-center justify-center text-[#FF671F] border border-white/10 shadow-inner">
                    <Sparkles size={20} />
                </div>
                <div>
                  <h3 className="font-black text-[11px] uppercase tracking-[0.2em] leading-none">DineBot Pro</h3>
                  <div className="flex items-center gap-1.5 mt-1.5">
                    <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                    <p className="text-[8px] text-blue-200 font-bold uppercase tracking-widest">Powered by Gemini Pro</p>
                  </div>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-colors"><ChevronDown size={20} /></button>
            </div>

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-5 space-y-5 no-scrollbar bg-gradient-to-b from-transparent to-black/20">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] rounded-[1.5rem] px-4 py-3 text-[11px] leading-relaxed shadow-lg ${
                      msg.role === 'user' 
                      ? 'bg-[#0033A0] text-white rounded-tr-none border border-white/10' 
                      : 'bg-white/5 text-slate-200 border border-white/10 rounded-tl-none backdrop-blur-md'
                  }`}>
                    {formatMessageText(msg.text)}
                  </div>
                  <span className="text-[7px] text-slate-600 font-black uppercase tracking-widest mt-1.5 px-2">
                    {msg.role === 'user' ? 'You' : 'DineBot'} • {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start items-center gap-2">
                    <div className="bg-white/5 border border-white/10 rounded-2xl px-4 py-3 flex gap-1.5">
