            {/* Input Area */}
            <div className="p-4 bg-[#0a0d14] border-t border-white/5 flex gap-3">
              <input 
                type="text" value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyDown={e => e.key === 'Enter' && handleSend()} 
                placeholder="Ask about snacks, spicy food, or prices..." 
                className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 text-[11px] font-medium text-white outline-none placeholder:text-slate-600 focus:border-[#FF671F]/50 transition-colors" 
              />
              <button 
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="w-12 h-12 bg-[#FF671F] text-white rounded-2xl flex items-center justify-center disabled:opacity-30 disabled:grayscale shadow-lg shadow-orange-500/20 active:scale-90 transition-all"
              >
                <Send size={18} />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

