          <div className="space-y-2"><p className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Select Account Type</p><div className="flex gap-2"> {['Student', 'Faculty', 'Staff'].map(type => ( <button key={type} onClick={() => setForm({...form, userType: type})} className={`flex-1 py-3 rounded-xl text-[9px] font-black border transition-all ${form.userType === type ? 'bg-[#FF671F] border-[#FF671F] text-white shadow-lg' : 'bg-white/5 border-white/10 text-slate-500 hover:bg-white/10'}`}> {type} </button> ))} </div></div>
          <Input label={form.userType === 'Faculty' ? 'Academic Department' : 'Academic Course'} value={form.course || form.department} onChange={(e:any) => setForm({...form, course: e.target.value, department: e.target.value})} />
          <div className="grid grid-cols-2 gap-3"><Input label="Age" type="number" value={form.age} onChange={(e:any) => setForm({...form, age: parseInt(e.target.value)})} /><Input label="Mobile Phone" value={form.phone} onChange={(e:any) => setForm({...form, phone: e.target.value})} /></div>
          <Input label="Residential Address" value={form.address} onChange={(e:any) => setForm({...form, address: e.target.value})} />
          <Button className="w-full h-14 rounded-2xl text-xs sticky bottom-0 mt-6 shadow-3xl" onClick={save}>Update Identity</Button>
        </div>
      </Modal>
    </div>
  );
};

const App: React.FC = () => (<HashRouter><AppContent /></HashRouter>);
export default App;

