const ProfileView: React.FC<any> = ({ user, setUser }) => {
  const [isEdit, setIsEdit] = useState(false);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({...user});

  // Update local form state if user changes externally
  useEffect(() => {
    setForm({...user});
  }, [user]);

  const save = async () => { 
    setLoading(true);
    try {
      // Use standard id field for upsert conflict resolution
      const { data, error } = await supabase
        .from('profiles')
        .upsert([{ 
          id: user.id, 
          name: form.name,
          userType: form.userType,
          course: form.course,
          department: form.department,
          age: form.age,
          phone: form.phone,
          address: form.address,
          email: form.email,
          avatar: form.avatar
        }], { onConflict: 'id' })
        .select()
        .single();

      if (!error) { 
        setUser(data); 
        setIsEdit(false); 
      } else { 
        console.error("Supabase Profile Error:", error);
        alert(`Failed to save: ${error.message}`); 
      }
    } catch (err) {
      console.error(err);
      alert("An unexpected error occurred while saving profile.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className={`${THEME.surface} p-8 rounded-[3rem] text-center relative overflow-hidden border-white/10`}>
