const ProfileView: React.FC<any> = ({ user, setUser }) => {
  const [isEdit, setIsEdit] = useState(false);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({...user});

  useEffect(() => {
    setForm({...user});
  }, [user]);

  const save = async () => { 
    if (!isSupabaseConfigured()) {
        setUser(form);
        setIsEdit(false);
        return;
    }

    setLoading(true);
    try {
      // Create a clean payload with correct types
      const payload = { 
        id: user.id, 
        name: form.name,
        userType: form.userType,
        course: form.course || null,
        department: form.department || null,
        age: form.age ? parseInt(form.age.toString()) : null,
        phone: form.phone || null,
        address: form.address || null,
        email: form.email || null,
        avatar: form.avatar || null
      };

      const { data, error } = await supabase
        .from('profiles')
        .upsert([payload], { onConflict: 'id' })
        .select()
        .single();

      if (error) { 
        console.error("Supabase Save Error Details:", error);
        // Stringify the error to show details if it's an object
        const errorMessage = typeof error === 'object' ? (error.message || JSON.stringify(error)) : error;
        alert(`Supabase Error: ${errorMessage}`); 
      } else { 
        setUser(data); 
        setIsEdit(false); 
      }
    } catch (err: any) {
      console.error("Unexpected Save Error:", err);
      alert(`Unexpected Error: ${err.message || 'Check console for details.'}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className={`${THEME.surface} p-8 rounded-[3rem] text-center relative overflow-hidden border-white/10`}>
        <div className="relative w-24 h-24 mx-auto mb-4">
