                            </div>
                          </motion.div>
                        ))}
                      </div>
                    </div>
                    <div>
                      <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Most Loved (5★)</h3>
                      <div className="grid grid-cols-2 gap-4 pb-20">
                        {menuItems.filter(i => i.isPopular).slice(0, 4).map(i => (
