// --- Auth Page ---
const AuthPage: React.FC<{ onAuth: (user: any) => void }> = ({ onAuth }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ email: '', password: '', name: '' });
  const [error, setError] = useState('');

  const handleAuth = async () => {
    setLoading(true);
    setError('');
    try {
      if (isLogin) {
        const { data, error: signInError } = await supabase.auth.signInWithPassword({
          email: form.email,
          password: form.password,
        });
        if (signInError) throw signInError;

        if (data?.user) {
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', data.user.id)
            .maybeSingle();

          if (profile) {
            onAuth(profile);
          } else {
            const newProfile = { 
              id: data.user.id, 
              name: data.user.user_metadata?.full_name || 'BUPC User',
              email: data.user.email,
              avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(data.user.user_metadata?.full_name || 'User')}&background=random`,
              userType: 'Student'
            };
            await supabase.from('profiles').insert([newProfile]);
            onAuth(newProfile);
          }
        }
      } else {
        const { data, error: signUpError } = await supabase.auth.signUp({
          email: form.email,
          password: form.password,
          options: { data: { full_name: form.name } }
        });
        if (signUpError) throw signUpError;

        if (data?.user) {
          const newProfile = { 
            id: data.user.id, 
