        >
          Add Review
        </button>
      </div>

      {filtered.length === 0 ? (
        <p className="text-[10px] text-slate-600 font-bold text-center py-6 border border-dashed border-white/5 rounded-2xl">No reviews yet. Share your experience!</p>
