const ProfileView: React.FC<any> = ({ user, setUser }) => {
  const [isEdit, setIsEdit] = useState(false);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({...user});
  const [showSaved, setShowSaved] = useState(false);

  useEffect(() => {
    setForm({...user});
  }, [user]);

  const save = async () => { 
    setLoading(true);
    try {
      const parsedAge = parseInt(form.age?.toString() || "");
      const ageValue = isNaN(parsedAge) ? null : parsedAge;

      const payload = { 
        name: String(form.name || ''),
        userType: String(form.userType || 'Student'),
        course: form.userType === 'Student' ? String(form.course || '') : null,
        department: form.userType !== 'Student' ? String(form.department || '') : null,
        age: ageValue,
        phone: form.phone ? String(form.phone) : null,
        address: form.address ? String(form.address) : null,
        email: form.email ? String(form.email) : null,
        avatar: form.avatar ? String(form.avatar) : null
      };

      // Guard for Demo User or no Supabase
      if (!isSupabaseConfigured() || user.id === 'u1') {
        const updatedUser = { ...user, ...payload };
        setUser(updatedUser);
        setIsEdit(false);
        setShowSaved(true);
        setTimeout(() => setShowSaved(false), 3000);
        return;
      }

      const { data, error } = await supabase
        .from('profiles')
        .update(payload)
        .eq('id', user.id)
        .select()
        .single();

      if (error) { 
        console.error("Supabase Save Error:", error);
        alert(`Failed to save: ${error.message}`); 
      } else if (data) { 
        setUser(data); 
        setIsEdit(false);
        setShowSaved(true);
        setTimeout(() => setShowSaved(false), 3000);
      }
    } catch (err: any) {
      console.error("Save Catch Error:", err);
      alert(`An error occurred: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className={`${THEME.surface} p-8 rounded-[3rem] text-center relative overflow-hidden border-white/10`}>
        <div className="relative w-24 h-24 mx-auto mb-4 group">
          <img src={user.avatar} className="w-full h-full rounded-[2rem] border-4 border-white/10 object-cover bg-white/5" alt="Profile" />
          <button onClick={() => setIsEdit(true)} className="absolute -bottom-2 -right-2 w-8 h-8 bg-[#FF671F] rounded-xl flex items-center justify-center border-4 border-[#050810] shadow-xl hover:scale-110 transition-transform"><Edit2 size={14} /></button>
        </div>
        <h2 className="text-lg font-black text-white">{user.name}</h2>
        <div className="mt-2"><span className="text-[8px] font-black uppercase text-[#FF671F] tracking-widest bg-[#FF671F]/10 px-4 py-1.5 rounded-full border border-[#FF671F]/20">{user.userType}</span></div>
      </div>

      <AnimatePresence>
        {showSaved && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="bg-green-500/10 border border-green-500/20 rounded-2xl p-3 flex items-center justify-center gap-2 text-green-500 text-[10px] font-black uppercase tracking-widest">
            <CheckCircle size={14} /> Profile Saved Successfully
          </motion.div>
        )}
      </AnimatePresence>

      <div className="space-y-3">
        <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-5 border-white/10`}>
          <div className="w-11 h-11 bg-blue-500/10 rounded-2xl flex items-center justify-center text-blue-400"><GraduationCap size={22} /></div>
          <div><p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-0.5">Identity</p><p className="text-xs font-black text-white">{user.course || user.department || 'BUPC Member'}</p></div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-4 border-white/10`}>
            <div className="w-9 h-9 bg-orange-500/10 rounded-xl flex items-center justify-center text-orange-400"><Clock size={18} /></div>
            <div><p className="text-[7px] font-black text-slate-500 uppercase">Age</p><p className="text-xs font-black text-white">{user.age || '—'}</p></div>
          </div>
          <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-4 border-white/10`}>
            <div className="w-9 h-9 bg-green-500/10 rounded-xl flex items-center justify-center text-green-400"><Phone size={18} /></div>
            <div><p className="text-[7px] font-black text-slate-500 uppercase">Phone</p><p className="text-[10px] font-black text-white">{user.phone || '—'}</p></div>
          </div>
        </div>
        <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-5 border-white/10`}>
          <div className="w-11 h-11 bg-purple-500/10 rounded-2xl flex items-center justify-center text-purple-400"><MapPin size={22} /></div>
          <div><p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-0.5">Home Address</p><p className="text-[10px] font-black text-white">{user.address || 'Polangui, Albay'}</p></div>
