// --- App Main Entry ---
const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [reviews, setReviews] = useState<Review[]>(MOCK_REVIEWS);
  const [stalls] = useState<Stall[]>(STALLS);
  const [menuItems] = useState<MenuItem[]>(MENU_ITEMS);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [loading, setLoading] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const checkSession = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).maybeSingle();
          if (profile) {
            setUser(profile);
            setOnboardingComplete(true);
          }
        }
      } catch (err) {
        console.error("Session Recovery Error:", err);
      } finally {
        setLoading(false);
      }
    };
    checkSession();
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = { id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`, items: [...items], subtotal, fee: 15, total, status: OrderStatus.PENDING, date: new Date(), paymentMethod: method };
    setOrders(prev => [newOrder, ...prev]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex items-center justify-center`}>
      <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }} className="text-[#FF671F]">
        <Loader size={48} />
      </motion.div>
    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white relative`}>
      <AnimatePresence mode="wait">
        {!onboardingComplete ? (
          <Routes location={location} key="onboarding">
            <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} />
          </Routes>
        ) : !user ? (
          <Routes location={location} key="auth">
            <Route path="*" element={<AuthPage onAuth={setUser} />} />
          </Routes>
        ) : (
          <>
            <AnimatePresence mode="wait">
              <Routes location={location} key={location.pathname}>
                <Route path="/" element={
                  <PageTransition>
                    <Header showLocation />
                    <div className="space-y-10">
                      <motion.div whileHover={{ scale: 1.01 }} className={`${THEME.surface} p-10 rounded-[3rem] relative overflow-hidden group`}>
                        <div className="relative z-10">
                          <p className="text-[9px] font-black uppercase text-[#FF671F] tracking-[0.2em] mb-3">Welcome Back</p>
                          <h1 className="text-3xl font-black mb-1 tracking-tighter">Stay Oragon,</h1>
                          <h1 className="text-3xl font-black mb-6 tracking-tighter text-blue-400">{user.name.split(' ')[0]}!</h1>
                          <Button size="md" className="rounded-xl" onClick={() => navigate('/menu')}>Explore Menu</Button>
                        </div>
                      </motion.div>
                      <div>
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Popular Stalls</h3>
                        <motion.div variants={staggerContainer} initial="hidden" animate="show" className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
                          {stalls.map(s => (
                            <motion.div key={s.id} variants={staggerItem} onClick={() => navigate(`/stalls/${s.id}`)} className="min-w-[200px] h-36 relative rounded-[2.5rem] overflow-hidden border border-white/10 group cursor-pointer">
                              <img src={s.image} className="w-full h-full object-cover group-hover:scale-110 transition-all duration-700" alt={s.name} />
                              <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent p-5 flex flex-col justify-end"><h4 className="text-[12px] font-black text-white">{s.name}</h4></div>
                            </motion.div>
                          ))}
                        </motion.div>
                      </div>
                      <div>
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">BUPC Faves</h3>
                        <motion.div variants={staggerContainer} initial="hidden" animate="show" className="grid grid-cols-2 gap-4 pb-20">
                          {menuItems.filter(i => i.isPopular).slice(0, 4).map(i => (
                            <motion.div key={i.id} variants={staggerItem}>
                              <ProductCard item={i} onAdd={addToCart} onClick={() => navigate(`/food/${i.id}`)} />
                            </motion.div>
                          ))}
                        </motion.div>
                      </div>
                    </div>
                  </PageTransition>
                } />
                <Route path="/menu" element={<PageTransition><MarketplaceView menuItems={menuItems} addToCart={addToCart} /></PageTransition>} />
                <Route path="/food/:id" element={<FoodDetailsView menuItems={menuItems} reviews={reviews} addToCart={addToCart} />} />
                <Route path="/cart" element={<PageTransition><Header title="Cart" /><CartView cart={cart} setCart={setCart} placeOrder={placeOrder} addToCart={addToCart} /></PageTransition>} />
                <Route path="/orders" element={<PageTransition><Header title="Orders" /><OrdersListView orders={orders} /></PageTransition>} />
                <Route path="/profile" element={<PageTransition><Header title="Profile" /><ProfileView user={user} setUser={setUser} /></PageTransition>} />
              </Routes>
            </AnimatePresence>
            <BottomNav cartCount={cart.length} />
            <ChatBot menuItems={menuItems} stalls={stalls} />
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

const CartView: React.FC<any> = ({ cart, setCart, placeOrder, addToCart }) => {
  const [method, setMethod] = useState<PaymentMethod>('GCash');
  const navigate = useNavigate();
  const handleCheckout = () => { placeOrder(cart, method); setCart([]); navigate('/orders'); };
  if (cart.length === 0) return <div className="text-center py-20 opacity-10"><ShoppingBag size={100} className="mx-auto" /><p className="font-black mt-4 uppercase">Bag is Empty</p></div>;
  return (
    <div className="space-y-4">
      {cart.map((i:any) => (
        <div key={i.id} className={`${THEME.surface} p-4 rounded-3xl flex items-center gap-4`}>
          <img src={i.image} className="w-16 h-16 rounded-2xl object-cover" alt={i.name} />
          <div className="flex-1">
            <h4 className="text-xs font-black">{i.name}</h4>
            <div className="flex justify-between items-center mt-2">
              <span className="text-sm font-black text-[#FF671F]">₱{i.price * i.quantity}</span>
              <div className="flex items-center gap-2 bg-white/5 p-1 rounded-xl">
                <button onClick={() => setCart((prev:any) => prev.map((item:any) => item.id === i.id ? {...item, quantity: Math.max(0, item.quantity - 1)} : item).filter((item:any) => item.quantity > 0))} className="w-6 h-6 rounded-lg bg-white/10">-</button>
                <span className="text-[10px] font-black w-3 text-center">{i.quantity}</span>
                <button onClick={() => addToCart(i)} className="w-6 h-6 rounded-lg bg-[#0033A0]">+</button>
              </div>
            </div>
          </div>
        </div>
      ))}
      <div className={`${THEME.surface} p-8 rounded-[3rem] space-y-6 mt-10`}>
        <div className="grid grid-cols-3 gap-2">
          {['GCash', 'PayMaya', 'Cash'].map((m) => (
            <button key={m} onClick={() => setMethod(m as any)} className={`p-3 rounded-2xl border text-[8px] font-black uppercase transition-all ${method === m ? 'bg-[#FF671F] border-[#FF671F] text-white' : 'bg-white/5 border-white/10 text-slate-500'}`}>{m}</button>
          ))}
        </div>
        <div className="pt-4 border-t border-dashed border-white/10 text-xl font-black flex justify-between">
          <span>Total</span><span className="text-[#FF671F]">₱{cart.reduce((s:any, i:any) => s + (i.price * i.quantity), 0) + 15}</span>
        </div>
        <Button className="w-full h-16 rounded-[2rem] text-lg font-black" onClick={handleCheckout}>Order Now</Button>
      </div>
    </div>
  );
};

