const ProfileView: React.FC<any> = ({ user, setUser, favorites, menuItems, addToCart }) => {
  const [isEdit, setIsEdit] = useState(false);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({...user});
  const [showSaved, setShowSaved] = useState(false);
  const navigate = useNavigate();

  const favoriteItems = menuItems.filter((item: MenuItem) => favorites.includes(item.id));

  useEffect(() => {
    setForm({...user});
  }, [user]);

  const save = async () => { 
    setLoading(true);
    try {
      const parsedAge = parseInt(form.age?.toString() || "");
      const ageValue = isNaN(parsedAge) ? null : parsedAge;

      const payload = { 
        name: String(form.name || ''),
        userType: String(form.userType || 'Student'),
        course: form.userType === 'Student' ? String(form.course || '') : null,
        department: form.userType !== 'Student' ? String(form.department || '') : null,
        age: ageValue,
        phone: form.phone ? String(form.phone) : null,
        address: form.address ? String(form.address) : null,
        email: form.email ? String(form.email) : null,
        avatar: form.avatar ? String(form.avatar) : null
      };

      if (!isSupabaseConfigured() || user.id === 'u1') {
        const updatedUser = { ...user, ...payload };
        setUser(updatedUser);
        setIsEdit(false);
        setShowSaved(true);
        setTimeout(() => setShowSaved(false), 3000);
        return;
      }

      const { data, error } = await supabase
        .from('profiles')
        .update(payload)
        .eq('id', user.id)
        .select()
        .single();

      if (error) { 
        console.error("Supabase Save Error:", error);
        alert(`Failed to save: ${error.message}`); 
      } else if (data) { 
        setUser(data); 
        setIsEdit(false);
        setShowSaved(true);
        setTimeout(() => setShowSaved(false), 3000);
      }
    } catch (err: any) {
      console.error("Save Catch Error:", err);
      alert(`An error occurred: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className={`${THEME.surface} p-8 rounded-[3rem] text-center relative overflow-hidden border-white/10`}>
        <div className="relative w-24 h-24 mx-auto mb-4 group">
          <img src={user.avatar} className="w-full h-full rounded-[2rem] border-4 border-white/10 object-cover bg-white/5" alt="Profile" />
          <button onClick={() => setIsEdit(true)} className="absolute -bottom-2 -right-2 w-8 h-8 bg-[#FF671F] rounded-xl flex items-center justify-center border-4 border-[#050810] shadow-xl hover:scale-110 transition-transform"><Edit2 size={14} /></button>
        </div>
        <h2 className="text-lg font-black text-white">{user.name}</h2>
        <div className="mt-2"><span className="text-[8px] font-black uppercase text-[#FF671F] tracking-widest bg-[#FF671F]/10 px-4 py-1.5 rounded-full border border-[#FF671F]/20">{user.userType}</span></div>
      </div>

      <AnimatePresence>
        {showSaved && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="bg-green-500/10 border border-green-500/20 rounded-2xl p-3 flex items-center justify-center gap-2 text-green-500 text-[10px] font-black uppercase tracking-widest">
            <CheckCircle size={14} /> Profile Saved Successfully
          </motion.div>
        )}
      </AnimatePresence>

      <div className="space-y-3">
        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] px-4">Identity Details</h3>
        <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-5 border-white/10`}>
          <div className="w-11 h-11 bg-blue-500/10 rounded-2xl flex items-center justify-center text-blue-400"><GraduationCap size={22} /></div>
          <div><p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-0.5">Academic Role</p><p className="text-xs font-black text-white">{user.course || user.department || 'BUPC Member'}</p></div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-4 border-white/10`}>
            <div className="w-9 h-9 bg-orange-500/10 rounded-xl flex items-center justify-center text-orange-400"><Clock size={18} /></div>
            <div><p className="text-[7px] font-black text-slate-500 uppercase">Age</p><p className="text-xs font-black text-white">{user.age || '—'}</p></div>
          </div>
          <div className={`${THEME.surface} p-5 rounded-3xl flex items-center gap-4 border-white/10`}>
            <div className="w-9 h-9 bg-green-500/10 rounded-xl flex items-center justify-center text-green-400"><Phone size={18} /></div>
            <div><p className="text-[7px] font-black text-slate-500 uppercase">Phone</p><p className="text-[10px] font-black text-white">{user.phone || '—'}</p></div>
          </div>
        </div>
      </div>

      {/* NEW Favorites Section */}
      <div className="space-y-4 pt-4">
        <div className="flex justify-between items-center px-4">
          <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em]">Your Favorites</h3>
          <span className="text-[8px] font-black text-orange-400 uppercase tracking-widest">{favoriteItems.length} Saved</span>
        </div>

        {favoriteItems.length > 0 ? (
          <motion.div 
            variants={staggerContainer}
            initial="hidden"
            animate="show"
            className="grid grid-cols-2 gap-4"
          >
            {favoriteItems.map((item: MenuItem) => (
              <motion.div key={item.id} variants={staggerItem}>
                <ProductCard 
                  item={item} 
                  onAdd={addToCart} 
                  onClick={() => navigate(`/food/${item.id}`)} 
                />
              </motion.div>
            ))}
          </motion.div>
        ) : (
          <div className={`${THEME.surface} p-10 rounded-[2.5rem] border-dashed border-white/10 flex flex-col items-center text-center`}>
            <Heart className="text-slate-700 mb-3" size={32} />
            <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">No favorites yet</p>
            <Link to="/menu" className="mt-4 text-[9px] font-black text-orange-400 uppercase tracking-widest border border-orange-400/20 px-4 py-2 rounded-xl bg-orange-400/5">Explore Menu</Link>
          </div>
        )}
      </div>

      <Button variant="outline" className="w-full h-14 rounded-2xl border-red-500/20 text-red-500 hover:bg-red-500/5 mt-8" onClick={() => setUser(null)}><LogOut size={18} className="mr-3" /> Sign Out</Button>

      <Modal isOpen={isEdit} onClose={() => setIsEdit(false)} title="Edit Profile">
        <div className="space-y-6 max-h-[75vh] overflow-y-auto no-scrollbar px-1">
          <div className="space-y-4">
            <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest text-center">Select Cartoon Avatar</p>
            <div className="grid grid-cols-4 gap-2">
              {PRESET_AVATARS.map((url, i) => (
                <motion.button key={i} whileTap={{ scale: 0.9 }} onClick={() => setForm({ ...form, avatar: url })} className={`relative aspect-square rounded-xl overflow-hidden border-2 transition-all ${form.avatar === url ? 'border-[#FF671F] scale-105 shadow-lg' : 'border-white/5 opacity-60'}`}>
                  <img src={url} className="w-full h-full object-cover bg-white/10" alt={`Avatar ${i}`} />
                  {form.avatar === url && <div className="absolute inset-0 bg-[#FF671F]/20 flex items-center justify-center"><Check size={12} className="text-white" /></div>}
                </motion.button>
              ))}
            </div>
          </div>

          <div className="space-y-4 pt-4 border-t border-white/5">
            <Input label="Full Name" value={form.name || ''} onChange={(e:any) => setForm({...form, name: e.target.value})} />
            <div className="space-y-2">
              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Type</p>
              <div className="flex gap-2"> 
                {['Student', 'Faculty', 'Staff'].map(type => ( 
                  <button key={type} onClick={() => setForm({...form, userType: type as any})} className={`flex-1 py-3 rounded-xl text-[9px] font-black border transition-all ${form.userType === type ? 'bg-[#FF671F] border-[#FF671F] text-white' : 'bg-white/5 border-white/10 text-slate-500'}`}>{type}</button> 
                ))} 
              </div>
            </div>
            {form.userType === 'Student' ? (
              <Input label="Course" value={form.course || ''} onChange={(e:any) => setForm({...form, course: e.target.value})} />
            ) : (
              <Input label="Department" value={form.department || ''} onChange={(e:any) => setForm({...form, department: e.target.value})} />
            )}
            <div className="grid grid-cols-2 gap-3">
              <Input label="Age" type="number" value={form.age || ''} onChange={(e:any) => setForm({...form, age: e.target.value})} />
              <Input label="Phone" value={form.phone || ''} onChange={(e:any) => setForm({...form, phone: e.target.value})} />
            </div>
            <Input label="Address" value={form.address || ''} onChange={(e:any) => setForm({...form, address: e.target.value})} />
          </div>

          <Button className="w-full h-14 rounded-2xl text-xs sticky bottom-0 shadow-3xl" onClick={save} disabled={loading}>
            {loading ? <Loader className="animate-spin" size={16} /> : "Update Profile"}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

// --- App Main Entry ---
const AppContent: React.FC = () => {
  const [user, setUser] = useState<UserType | any>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [reviews, setReviews] = useState<Review[]>(MOCK_REVIEWS);
  const [stalls] = useState<Stall[]>(STALLS);
  const [menuItems] = useState<MenuItem[]>(MENU_ITEMS);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [loading, setLoading] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const checkSession = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).maybeSingle();
          if (profile) {
            setUser(profile);
            setOnboardingComplete(true);
          }
        }
      } catch (err) {
        console.error("Session Recovery Error:", err);
      } finally {
        setLoading(false);
      }
    };
    checkSession();
  }, []);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const placeOrder = (items: CartItem[], method: PaymentMethod) => {
    const subtotal = items.reduce((s, i) => s + (i.price * i.quantity), 0);
    const total = subtotal + 15;
    const newOrder: Order = { id: `ORD-${Math.floor(Math.random() * 900000 + 100000)}`, items: [...items], subtotal, fee: 15, total, status: OrderStatus.PENDING, date: new Date(), paymentMethod: method };
    setOrders(prev => [newOrder, ...prev]);
  };

  const toggleFavorite = (id: string) => {
    setFavorites(prev => prev.includes(id) ? prev.filter(fid => fid !== id) : [...prev, id]);
  };

  if (loading) return (
    <div className={`h-screen ${THEME.bg} flex items-center justify-center`}>
      <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }} className="text-[#FF671F]">
        <Loader size={48} />
      </motion.div>
    </div>
  );

  return (
    <div className={`min-h-screen ${THEME.bg} text-white relative`}>
      <AnimatePresence mode="wait">
        {!onboardingComplete ? (
          <Routes location={location} key="onboarding">
            <Route path="*" element={<OnboardingPage onComplete={() => setOnboardingComplete(true)} />} />
          </Routes>
        ) : !user ? (
          <Routes location={location} key="auth">
            <Route path="*" element={<AuthPage onAuth={setUser} />} />
          </Routes>
        ) : (
          <>
            <AnimatePresence mode="wait">
              <Routes location={location} key={location.pathname}>
                <Route path="/" element={
                  <PageTransition>
                    <Header showLocation />
                    <div className="space-y-10">
                      <motion.div whileHover={{ scale: 1.01 }} className={`${THEME.surface} p-10 rounded-[3rem] relative overflow-hidden group`}>
                        <div className="relative z-10">
                          <p className="text-[9px] font-black uppercase text-[#FF671F] tracking-[0.2em] mb-3">Welcome Back</p>
                          <h1 className="text-3xl font-black mb-1 tracking-tighter">Stay Oragon,</h1>
                          <h1 className="text-3xl font-black mb-6 tracking-tighter text-blue-400">{user.name.split(' ')[0]}!</h1>
                          <Button size="md" className="rounded-xl" onClick={() => navigate('/menu')}>Explore Menu</Button>
                        </div>
                      </motion.div>
                      <div>
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">Popular Stalls</h3>
                        <motion.div variants={staggerContainer} initial="hidden" animate="show" className="flex gap-4 overflow-x-auto no-scrollbar -mx-4 px-4 pb-6">
                          {stalls.map(s => (
                            <motion.div key={s.id} variants={staggerItem} onClick={() => navigate(`/stalls/${s.id}`)} className="min-w-[200px] h-36 relative rounded-[2.5rem] overflow-hidden border border-white/10 group cursor-pointer">
                              <img src={s.image} className="w-full h-full object-cover group-hover:scale-110 transition-all duration-700" alt={s.name} />
                              <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent p-5 flex flex-col justify-end"><h4 className="text-[12px] font-black text-white">{s.name}</h4></div>
                            </motion.div>
                          ))}
                        </motion.div>
                      </div>
                      <div>
                        <h3 className="text-[9px] font-black uppercase text-slate-500 tracking-[0.3em] mb-6 px-4">BUPC Faves</h3>
                        <motion.div variants={staggerContainer} initial="hidden" animate="show" className="grid grid-cols-2 gap-4 pb-20">
                          {menuItems.filter(i => i.isPopular).slice(0, 4).map(i => (
                            <motion.div key={i.id} variants={staggerItem}>
                              <ProductCard item={i} onAdd={addToCart} onClick={() => navigate(`/food/${i.id}`)} />
                            </motion.div>
                          ))}
                        </motion.div>
                      </div>
                    </div>
                  </PageTransition>
                } />
                <Route path="/menu" element={<PageTransition><MarketplaceView menuItems={menuItems} addToCart={addToCart} /></PageTransition>} />
                <Route path="/food/:id" element={<FoodDetailsView menuItems={menuItems} reviews={reviews} addToCart={addToCart} />} />
                <Route path="/cart" element={<PageTransition><Header title="Cart" /><CartView cart={cart} setCart={setCart} placeOrder={placeOrder} addToCart={addToCart} /></PageTransition>} />
                <Route path="/orders" element={<PageTransition><Header title="Orders" /><OrdersListView orders={orders} /></PageTransition>} />
                <Route path="/profile" element={<PageTransition><Header title="Profile" /><ProfileView user={user} setUser={setUser} favorites={favorites} menuItems={menuItems} addToCart={addToCart} /></PageTransition>} />
              </Routes>
            </AnimatePresence>
            <BottomNav cartCount={cart.length} />
            <ChatBot menuItems={menuItems} stalls={stalls} />
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

const CartView: React.FC<any> = ({ cart, setCart, placeOrder, addToCart }) => {
  const [method, setMethod] = useState<PaymentMethod>('GCash');
  const navigate = useNavigate();
  const handleCheckout = () => { placeOrder(cart, method); setCart([]); navigate('/orders'); };
  if (cart.length === 0) return <div className="text-center py-20 opacity-10"><ShoppingBag size={100} className="mx-auto" /><p className="font-black mt-4 uppercase">Bag is Empty</p></div>;
  return (
    <div className="space-y-4">
      {cart.map((i:any) => (
        <div key={i.id} className={`${THEME.surface} p-4 rounded-3xl flex items-center gap-4`}>
          <img src={i.image} className="w-16 h-16 rounded-2xl object-cover" alt={i.name} />
          <div className="flex-1">
            <h4 className="text-xs font-black">{i.name}</h4>
            <div className="flex justify-between items-center mt-2">
              <span className="text-sm font-black text-[#FF671F]">₱{i.price * i.quantity}</span>
              <div className="flex items-center gap-2 bg-white/5 p-1 rounded-xl">
                <button onClick={() => setCart((prev:any) => prev.map((item:any) => item.id === i.id ? {...item, quantity: Math.max(0, item.quantity - 1)} : item).filter((item:any) => item.quantity > 0))} className="w-6 h-6 rounded-lg bg-white/10">-</button>
                <span className="text-[10px] font-black w-3 text-center">{i.quantity}</span>
                <button onClick={() => addToCart(i)} className="w-6 h-6 rounded-lg bg-[#0033A0]">+</button>
              </div>
            </div>
          </div>
        </div>
      ))}
      <div className={`${THEME.surface} p-8 rounded-[3rem] space-y-6 mt-10`}>
        <div className="grid grid-cols-3 gap-2">
          {['GCash', 'PayMaya', 'Cash'].map((m) => (
            <button key={m} onClick={() => setMethod(m as any)} className={`p-3 rounded-2xl border text-[8px] font-black uppercase transition-all ${method === m ? 'bg-[#FF671F] border-[#FF671F] text-white' : 'bg-white/5 border-white/10 text-slate-500'}`}>{m}</button>
          ))}
        </div>
        <div className="pt-4 border-t border-dashed border-white/10 text-xl font-black flex justify-between">
          <span>Total</span><span className="text-[#FF671F]">₱{cart.reduce((s:any, i:any) => s + (i.price * i.quantity), 0) + 15}</span>
        </div>
        <Button className="w-full h-16 rounded-[2rem] text-lg font-black" onClick={handleCheckout}>Order Now</Button>
      </div>
    </div>
  );
};

const App: React.FC = () => (<HashRouter><AppContent /></HashRouter>);
export default App;
